(function(w){w.__PC_DUOC_CHUNKS=w.__PC_DUOC_CHUNKS||{};w.__PC_DUOC_CHUNKS["jci-06"]=[{"c":"MMU.04.01","ch":"MMU","t":"Bệnh viện xác định các hoạt động kê đơn, đặt hàng và ghi chép an toàn và xác định các yếu tố của một đơn đặt hàng hoặc đơn thuốc hoàn chỉnh.","p":"Một nguyên nhân phổ biến gây ra các biến cố bất lợi trong bối cảnh bệnh viện là lỗi dùng thuốc. Các chiến\nlược nhằm giảm sự thay đổi trong việc viết đơn thuốc, chẳng hạn như xác định các yếu tố bắt buộc của đơn\nthuốc hoặc toa thuốc hoàn chỉnh, giúp giảm nguy cơ\nsai sót về thuốc và cải thiện sự an toàn của bệnh nhân. Một nghiên cứu gần đây đã báo cáo rằng \"lỗi dùng\nthuốc thường gặp nhất ở giai đoạn chỉ định hoặc kê đơn. Các lỗi điển hình bao gồm bác sĩ chăm sóc sức khỏe\nviết sai thuốc, sai đường dùng hoặc liều dùng hoặc sai tần suất. Những lỗi chỉ định này chiếm gần 50% các\nlỗi dùng thuốc\". Trong hồ sơ giấy, đơn thuốc hoặc lệnh dùng thuốc không rõ ràng là một trong những\nnguyên nhân gây ra lỗi dùng thuốc gây nguy hiểm cho sự an toàn của bệnh nhân và có thể làm chậm trễ quá\ntrình điều trị. Các chiến lược nhằm giảm tình trạng không rõ ràng của các lệnh viết là rất quan trọng để giảm\nnguy cơ sai sót về thuốc. Việc kê đơn, chỉ định và sao chép an toàn được hướng dẫn bởi các chính sách và quy\ntrình của bệnh viện. Nhân viên y tế, điều dưỡng, dược sĩ và hành chính hợp tác để\nphát triển và giám sát các chính sách và quy trình. Các nhân viên có liên quan được đào tạo về các hoạt động\nkê đơn, chỉ định và sao chép chính xác.\n\nTất cả các đơn thuốc và đơn thuốc đều có tên thuốc, liều lượng và/hoặc độ mạnh, tần suất và đường dùng.\nVí dụ, thuốc có thể là một phần của bệnh sử. Ngoài ra, sau đây là các ví dụ về thông tin bổ sung mà đơn thuốc\nphải có khi cần thiết:\n• Đơn thuốc PRN (pro re nata, hoặc \"khi cần\"): chỉ định sử dụng, hướng dẫn chi tiết cho các đơn thuốc\nchồng chéo (ví dụ, nhiều hơn một loại thuốc giảm đau)\n• Đơn thuốc dựa trên cân nặng hoặc được điều chỉnh theo cách khác: ví dụ, trẻ em, người già yếu, người có\nchức năng thận suy yếu, bệnh nhân ung thư\n• Điều chỉnh theo phạm vi điều trị: ví dụ, liều dùng có thể cần được cập nhật dựa trên các giá trị xét nghiệm\nđối với các loại thuốc cụ thể, chẳng hạn như truyền heparin hoặc phenytoin.\n\nCó các quy trình để quản lý đơn thuốc. Do đó, tiêu chuẩn này đặt ra các kỳ vọng trên toàn bệnh viện đối với\nđơn thuốc. Các quy trình được phản ánh trong các đơn thuốc hoàn chỉnh được nhập vào hồ sơ y tế, hiệu\nthuốc\nhoặc đơn vị phân phối nhận thông tin cần thiết để phân phối và việc quản lý thuốc dựa trên đơn thuốc hoàn\nchỉnh.\n\nMỗi loại thuốc được kê đơn phải có chẩn đoán, tình trạng hoặc chỉ định sử dụng. Thông tin này có thể nằm\nở bất kỳ đâu trong hồ sơ y tế và không nhất thiết phải có trong đơn thuốc.\n\nKhi quản lý thuốc đã chuẩn độ, các thông tin sau đây phải có trong đơn thuốc chuẩn độ: tên thuốc, đường\ndùng thuốc, tốc độ truyền ban đầu (liều/đơn vị thời gian), đơn vị gia tăng mà tốc độ hoặc liều có thể tăng\nhoặc giảm, tần suất có thể thay đổi tốc độ hoặc liều, tốc độ hoặc liều tối đa khi truyền và biện pháp lâm sàng\nkhách quan được sử dụng để hướng dẫn thay đổi. Ví dụ về các biện pháp lâm sàng khách quan được sử dụng\nđể hướng dẫn thay đổi chuẩn độ bao gồm đo huyết áp, giao thức heparin dựa trên cân nặng, thang đo kích\nđộng-an thần Richmond (RASS) và Công cụ quan sát cơn đau chăm sóc đặc biệt (CPOT).\n\nBệnh viện thực hiện chính sách bao gồm một số loại đơn thuốc nhất định. Các loại được xác định và liệt kê\nnhư sau:\n•\nLệnh theo nhu cầu (PRN): Lệnh được thực hiện dựa trên sự xuất hiện của một chỉ định hoặc triệu\nchứng cụ thể\n•\nLệnh thường trực: Lệnh dùng thuốc được viết sẵn với các hướng dẫn cụ thể từ bác sĩ hoặc người hành\nnghề được cấp phép khác để dùng thuốc cho một người trong những trường hợp được xác định rõ ràng\n•\nLệnh dừng tự động: Lệnh bao gồm ngày hoặc giờ ngừng dùng thuốc\n•\nLệnh chuẩn độ: Lệnh trong đó liều lượng được tăng dần hoặc giảm dần để đáp ứng với\n•\ntình trạng của bệnh nhân\n•\nLệnh giảm dần: Lệnh trong đó liều lượng được giảm đi một lượng cụ thể với mỗi khoảng cách dùng\nthuốc\n•\nLệnh phạm vi: Lệnh trong đó liều lượng hoặc khoảng cách dùng thuốc thay đổi trong một phạm vi được\nquy định, tùy thuộc vào\n•\ntình hình hoặc tình trạng của bệnh nhân\n\n•\nLệnh đã ký và giữ: Lệnh thuốc mới được viết sẵn (giữ) và hướng dẫn cụ thể từ bác sĩ hoặc người\nhành nghề được cấp phép khác để dùng thuốc cho bệnh nhân trong những trường hợp được xác\nđịnh rõ ràng, có hiệu lực khi lệnh được ban hành vào ngày và giờ cụ thể\n•\nLệnh cho thuốc pha chế hoặc hỗn hợp thuốc không có sẵn trên thị trường\n•\nLệnh cho các thiết bị liên quan đến thuốc (ví dụ: máy phun khí dung, ống thông)\n•\nLệnh cho thuốc khi xuất viện hoặc chuyển viện\n•\nLệnh cho thuốc cản quang\n\nNếu áp dụng với dịch vụ chăm sóc, điều trị và dịch vụ mà bệnh viện cung cấp, các lệnh bổ sung sau đây\nđược bao gồm trong chính sách:\n•\nLệnh cho thuốc đang nghiên cứu\n•\nLệnh cho các sản phẩm thảo dược\n•\nLệnh cho dược phẩm phóng xạ","m":[],"sec":"Đặt hàng và kê đơn"},{"c":"MMU.04.02","ch":"MMU","t":"Bệnh viện có quy trình đối chiếu thuốc.","p":"Việc kê đơn và ghi chép đơn thuốc là một quá trình quan trọng để quản lý thuốc an toàn cho bệnh nhân và giảm\nnguy cơ xảy ra các tác dụng phụ. Bệnh nhân nhập viện thường dùng nhiều loại thuốc tại nhà. Việc có được danh\nsách chính xác các loại thuốc đó và ghi lại chúng trong hồ sơ y tế của bệnh nhân giúp giảm nguy cơ xảy ra tác\ndụng phụ.\n\nSự khác biệt về thuốc có thể ảnh hưởng đến kết quả điều trị của bệnh nhân. Có thể khó để có được danh sách\nđầy đủ từ mọi bệnh nhân trong một lần khám và độ chính xác phụ thuộc vào khả năng và thiện chí cung cấp\nthông tin này của bệnh nhân. Một nỗ lực đáng tin cậy để thu thập thông tin này được công nhận là đáp ứng được\nmục đích của yêu cầu. Ví dụ về một nỗ lực đáng tin cậy có thể bao gồm liên hệ với hiệu thuốc và/hoặc thành viên\ngia đình của bệnh nhân hoặc tham khảo ý kiến bác sĩ chính của bệnh nhân.\n\nĐối chiếu thuốc được định nghĩa là quá trình xác định các loại thuốc hiện đang được một cá nhân sử dụng. Các\nloại thuốc này được so sánh với các loại thuốc mới được kê đơn và sự khác biệt được xác định và đối chiếu. Các\nloại thông tin mà bác sĩ lâm sàng sử dụng để đối chiếu thuốc bao gồm nhưng không giới hạn ở\ntên thuốc, liều dùng, tần suất, đường dùng và mục đích. Bệnh viện cần xác định thông tin cần thu thập để đối\nchiếu thuốc hiện tại và thuốc mới được kê đơn và kê đơn thuốc an toàn trong tương lai. Thông tin về chiều cao và\ncân nặng không được thu thập cho mọi bệnh nhân. Tuy nhiên, bệnh viện phải có quy trình để đảm bảo rằng tất\ncả thông tin cần thiết để kê đơn an toàn đều được thu thập và ghi lại trong hồ sơ y tế của bệnh nhân (xem\nthêm MMU.04.01). Điều này có thể thực hiện được bằng cách thu thập chiều cao, cân nặng, độ tuổi và các thông\ntin khác từ mọi bệnh nhân; bằng cách xác định các nhóm bệnh nhân (ví dụ: suy thận ở trẻ em, ung thư, bỏng, tim\nmạch); và bằng cách xác định các loại thuốc (ví dụ: hóa trị hoặc các loại thuốc khác được tính theo diện tích bề\nmặt cơ thể [BSA]) mà thông tin cụ thể phải được thu thập, chẳng hạn như chiều cao và cân nặng.\n\nCác biện pháp quản lý thuốc tốt bao gồm việc xem xét một loại thuốc mới được đề xuất so với danh sách các loại\nthuốc mà bệnh nhân hiện đang dùng để cải thiện chất lượng và tính an toàn khi thêm một loại thuốc mới vào\nphác đồ điều trị của bệnh nhân và giảm nguy cơ xảy ra tác dụng phụ của thuốc. Danh sách tất cả các loại thuốc\nhiện tại được ghi lại trong hồ sơ y tế của bệnh nhân và có sẵn cho hiệu thuốc, y tá và bác sĩ. Bệnh viện thiết\nlập một quy trình để so sánh danh sách thuốc bệnh nhân đã dùng trước khi nhập viện với đơn thuốc ban đầu.","m":[],"sec":"Đặt hàng và kê đơn"},{"c":"MMU.05.00","ch":"MMU","t":"Thuốc được chuẩn bị và phân phối trong môi trường an toàn và sạch sẽ.","p":"Một số loại thuốc và dung dịch cần được pha chế theo các hướng dẫn rất cụ thể để ngăn ngừa nhiễm bẩn\nvà nguy cơ nhiễm trùng cho bệnh nhân. Nhà thuốc hoặc dịch vụ dược phẩm và những đơn vị khác được\nđào tạo và có kinh nghiệm phù hợp sẽ pha chế và phân phối thuốc trong môi trường sạch sẽ và an toàn, tuân\nthủ luật pháp, quy định và tiêu chuẩn hành nghề. Bệnh viện xác định các tiêu chuẩn hành nghề để có môi\ntrường pha chế và phân phối thuốc an toàn và sạch sẽ.\n\nVí dụ, các tiêu chuẩn hành nghề có thể bao gồm cách vệ sinh khu vực pha chế thuốc và thời điểm cần đeo\nkhẩu trang hoặc sử dụng tủ hút khí tầng trong quá trình pha chế thuốc. Nhân viên pha chế và pha chế các\nloại thuốc này được đào tạo về các nguyên tắc pha chế thuốc và kỹ thuật vô trùng. Tương tự như vậy,\nphòng áp suất dương hoặc âm và tủ hút khí tầng đều có sẵn\nvà được sử dụng khi được các cơ sở hành nghề chỉ định; ví dụ, trong quá trình pha chế thuốc vô trùng, hỗn\nhợp dinh dưỡng ngoài đường tiêu hóa hoàn toàn (TPN), hóa trị và gây tê ngoài màng cứng. Do nhu cầu về\nkhả năng tạo áp suất dương và áp suất âm và tủ hút khí tầng để pha chế các loại thuốc này, nên chỉ pha chế\nchúng tại hiệu thuốc trừ khi đơn vị chăm sóc bệnh nhân được trang bị thiết bị an toàn cần thiết và có nhân\nviên được đào tạo (ví dụ: đơn vị ung thư chuyên khoa). Một tình huống phổ biến trong pha chế thuốc có\nnguy cơ lây truyền các bệnh truyền nhiễm là sử dụng lọ thuốc dùng một lần và nhiều liều cho nhiều bệnh\nnhân. Việc sử dụng sai các lọ thuốc này đã gây hại cho từng bệnh nhân thông qua các trường hợp xảy ra và\nbùng phát các tác nhân gây bệnh qua đường máu và các bệnh nhiễm trùng liên quan ở cả bệnh nhân nội trú\nvà ngoại trú—bao gồm vi-rút viêm gan B và C, viêm màng não và áp xe ngoài màng cứng.\n\nPha chế vô trùng được định nghĩa là kết hợp, trộn, pha loãng, pha loãng, gộp, tái tạo, đóng gói lại hoặc thay\nđổi thuốc hoặc chất thuốc số lượng lớn để tạo ra thuốc vô trùng. Đảm bảo môi trường pha chế an toàn đòi\nhỏi sự tổ chức và siêng năng. Các yêu cầu về cơ sở nhằm mục đích thiết lập một môi trường an toàn cho các\nchế phẩm vô trùng pha chế (CSP). Phân loại độ sạch không khí của Tổ chức Tiêu chuẩn hóa Quốc tế (ISO)\nvề môi trường pha chế là một biện pháp quan trọng có thể bị ảnh hưởng bởi thiết kế cơ sở; do đó, kiến\ntrúc cơ sở được tính đến khi thiết lập khu vực pha chế vô trùng. Giám sát môi trường và tài liệu liên quan\nphải được hoàn thành theo định kỳ để đảm bảo có các biện pháp kiểm soát môi trường và nhân sự đầy đủ\nnhằm ngăn ngừa ô nhiễm CSP.\n\nPha chế thuốc nguy hiểm là pha chế các loại thuốc nguy hiểm có nguy cơ phơi nhiễm cho bệnh nhân và\nnhân viên y tế (ví dụ, thuốc gây ung thư, gây quái thai hoặc có độc tính phát triển, độc tính sinh sản, độc\ntính đối với cơ quan ở liều thấp, độc tính di truyền hoặc cấu trúc và hồ sơ độc tính của thuốc mới bắt\nchước các loại thuốc nguy hiểm hiện có). Bệnh viện phải tuân thủ tất cả các yêu cầu áp dụng dựa trên luật\npháp và quy định, tiêu chuẩn hành nghề chuyên môn và chính sách của bệnh viện, bao gồm giáo dục, đào tạo\nvà trách nhiệm của nhân viên xử lý thuốc nguy hiểm; kiểm soát cơ sở và kỹ thuật; quy trình vô hiệu hóa,\nkhử nhiễm và vệ sinh; kiểm soát tràn; và lập hồ sơ về những điều trên. Các tiêu chuẩn này áp dụng cho tất\ncả nhân viên chăm sóc sức khỏe tiếp nhận, chuẩn bị, quản lý, vận chuyển hoặc tiếp xúc với các loại thuốc\nnguy hiểm và tất cả các môi trường mà chúng được xử lý.\n\nTài liệu xác định các tiêu chuẩn và thực hành an toàn khi sử dụng lọ thuốc đơn liều và đa liều; ví dụ, đảm\nbảo rằng tất cả kim tiêm và ống tiêm chỉ được sử dụng cho một bệnh nhân và không bao giờ đưa kim tiêm\nhoặc ống tiêm đã qua sử dụng vào lọ thuốc. Các loại thuốc không yêu cầu các biện pháp an toàn cụ thể của\nhiệu thuốc như phòng pha chế vô trùng hoặc tủ hút khí tầng và được lưu trữ và phân phối tại các khu vực\nbên ngoài hiệu thuốc (ví dụ: đơn vị chăm sóc bệnh nhân) tuân thủ các biện pháp vệ sinh tương tự như yêu\ncầu tại hiệu thuốc. Ngoài ra, các khu vực phân phối thuốc nằm trong các đơn vị chăm sóc bệnh nhân phải\nkhông có sự lộn xộn và mất tập trung.","m":[],"sec":"Chuẩn bị và phân phối"},{"c":"MMU.05.01","ch":"MMU","t":"Quy trình của bệnh viện đối với dược phẩm phóng xạ tuân thủ theo luật pháp, quy định và hướng dẫn.","p":"Một quy trình chuẩn bị và phân phối dược phẩm phóng xạ theo luật pháp, quy định và hướng dẫn giúp theo dõi\ntính an toàn và hiệu quả của thuốc phóng xạ dùng để chăm sóc và điều trị bệnh nhân trong bệnh viện. Dược\nđiển Hoa Kỳ và Danh mục thuốc quốc gia (USP-NF) định nghĩa dược phẩm phóng xạ là “dạng bào chế thành\nphẩm có chứa chất phóng xạ kết hợp với một hoặc nhiều thành phần khác và dùng để chẩn đoán, phân loại\nbệnh, theo dõi điều trị hoặc cung cấp liệu pháp. Dược phẩm phóng xạ bao gồm bất kỳ bộ thuốc thử không\nphóng xạ hoặc máy phát phóng xạ nào dùng để chuẩn bị bất kỳ chất nào như vậy. Các thuật ngữ 'dược phẩm\nphóng xạ' và 'thuốc phóng xạ' thường được sử dụng thay thế cho nhau.\" Theo trường hợp áp dụng, dược\nphẩm phóng xạ phải được vận chuyển đến bệnh viện trong thiết bị che chắn phù hợp. Hơn nữa, khi xử lý,\nchuẩn bị và phân phối dược phẩm phóng xạ, việc tuân thủ các luật và quy định về bức xạ tại địa phương về an\ntoàn cho nhân viên và môi trường là rất quan trọng.","m":[],"sec":"Chuẩn bị và phân phối"},{"c":"MMU.05.02","ch":"MMU","t":"Đơn thuốc hoặc đơn đặt hàng thuốc được xem xét để đảm bảo tính phù hợp.","p":"Quản lý thuốc tốt bao gồm hai lần xem xét từng đơn thuốc hoặc lệnh:\n• Tính phù hợp của thuốc đối với bệnh nhân và nhu cầu lâm sàng của họ được thực hiện tại thời điểm\nthuốc được kê đơn hoặc lệnh\n• Xác minh tại thời điểm dùng thuốc rằng thuốc chính xác như đã kê đơn hoặc lệnh\n\nMỗi loại thuốc mới được kê đơn hoặc lệnh đều được xem xét tính phù hợp, bao gồm cả khi liều lượng hoặc\ncác yếu tố phù hợp khác được ghi chú bên dưới thay đổi; ví dụ, khi thuốc mới được kê đơn và có thể xảy ra\ntình trạng trùng lặp điều trị hoặc khi có thể xảy ra tương tác thuốc tiềm ẩn. Bệnh viện xác định thông tin cụ\nthể của bệnh nhân là bắt buộc để xem xét tính phù hợp của đơn thuốc hoặc lệnh. Ví dụ, nếu thuốc mới được\nkê đơn có thể ảnh hưởng đến thận hoặc gan, thì việc xem xét tính phù hợp bao gồm thông tin lâm sàng cụ\nthể về chức năng thận và gan của bệnh nhân, cũng như thời điểm các chức năng của các cơ quan này thay\nđổi.\n\nQuy trình tiến hành xem xét tính phù hợp của đơn thuốc hoặc lệnh trước khi cấp phát bao gồm đánh giá tính\nphù hợp của thuốc, liều lượng, tần suất và đường dùng; trùng lặp điều trị; dị ứng hoặc nhạy cảm và tương\ntác giữa thuốc và các loại thuốc khác hoặc thực phẩm; sự khác biệt so với tiêu chuẩn sử dụng của bệnh viện;\ncân nặng của bệnh nhân và các thông tin sinh lý khác; tác động hiện tại hoặc tiềm ẩn như được chỉ ra bởi các\ngiá trị xét nghiệm; và các chống chỉ định khác.\n\nBệnh viện quyết định cách thức tiến hành đánh giá tính phù hợp. Ví dụ, đánh giá tính phù hợp có thể được\ntiến hành bởi những cá nhân có năng lực thực hiện thông qua giáo dục và đào tạo, chẳng hạn như dược sĩ\nđược cấp phép, hoặc theo quy định của đặc quyền cụ thể để thực hiện đánh giá tính phù hợp cho các bác sĩ\nchăm sóc sức khỏe độc lập có đào tạo và năng lực thực hiện quy trình đánh giá tính phù hợp; hoặc cho y tá\nhoặc các chuyên gia khác có đào tạo và năng lực đã được chứng minh trong quy trình đánh giá.\n\nBệnh viện có thể chọn sử dụng các chương trình hỗ trợ quyết định lâm sàng liên quan đến quản lý thuốc để\ntăng cường quy trình hoặc tiến hành quy trình đánh giá tính phù hợp kết hợp với một chuyên gia được cấp\nphép hoặc cá nhân được đào tạo được chỉ định; tuy nhiên, chỉ riêng hỗ trợ quyết định lâm sàng không đủ để\nđánh giá tính phù hợp đầy đủ và do đó không được chấp nhận là phương án thay thế để đáp ứng yêu cầu tiến\nhành đánh giá tính phù hợp. Ví dụ, nhiều hệ thống đặt thuốc điện tử được thiết kế để xem xét đơn thuốc để\nbiết đầy đủ các yếu tố của đánh giá tính phù hợp, bao gồm thông tin lâm sàng cụ thể của bệnh nhân và cung\ncấp cảnh báo cho cá nhân đặt thuốc về chống chỉ định kê đơn thuốc. Khi cá nhân đặt thuốc ghi đè cảnh báo,\nbệnh viện sẽ xây dựng quy trình để bác sĩ được đào tạo và chứng minh năng lực đánh giá đầy đủ đơn thuốc.\nBác sĩ này phải đánh giá tính phù hợp ngay cả khi hoàn cảnh không lý tưởng. Ví dụ, nếu hiệu thuốc trung tâm\nhoặc hiệu thuốc đơn vị không mở cửa hoặc thuốc sẽ được phân phối từ kho tại khoa hoặc phòng khám, đánh\ngiá tính phù hợp có thể được tiến hành kết hợp với đánh giá xác minh khi cá nhân đặt thuốc sẽ cấp thuốc và\ntheo dõi bệnh nhân.\n\nKhi cá nhân đặt thuốc không có mặt để cấp thuốc và theo dõi bệnh nhân, các yếu tố quan trọng của đánh giá\ntính phù hợp có thể được thực hiện bởi những cá nhân được đào tạo và có năng lực khác để cấp liều thuốc\nđầu tiên. Tuy nhiên, toàn bộ quá trình đánh giá tính phù hợp phải được thực hiện bởi một dược sĩ được cấp\nphép hoặc một chuyên gia được cấp phép khác, chẳng hạn như y tá hoặc bác sĩ, có đủ năng lực về kiến thức\ncần thiết để đánh giá tính phù hợp đầy đủ, trong vòng 24 giờ.\n\nCác yếu tố quan trọng của quá trình đánh giá tính phù hợp có thể được thực hiện bởi những cá nhân được đào tạo\ncó giấy phép khác trong thời gian hiệu thuốc không có mặt. Những cá nhân này cần được đào tạo có tài liệu về việc\nthực hiện các yếu tố quan trọng của quá trình đánh giá tính phù hợp và sẽ được hỗ trợ bởi các tài liệu tham khảo,\nchương trình máy tính và các nguồn lực khác. Do đó, khi bác sĩ gọi đơn thuốc mới vào ban đêm cho bệnh nhân, cá\nnhân được đào tạo sẽ viết ra và đọc lại đơn thuốc, sau đó tiến hành đánh giá tính phù hợp đối với các yếu tố quan\ntrọng đã xác định. Một dược sĩ được cấp phép hoặc chuyên gia được cấp phép khác, chẳng hạn như y tá hoặc bác sĩ\ncó năng lực về kiến thức cần thiết để đánh giá tính phù hợp đầy đủ, sẽ được yêu cầu đánh giá lần thứ hai trong\nvòng 24 giờ.\n\nCó thể có những trường hợp mà quá trình đánh giá tính phù hợp đầy đủ không thực tế, chẳng hạn như trong\ntrường hợp khẩn cấp hoặc khi bác sĩ chỉ định có mặt để chỉ định, thực hiện và theo dõi bệnh nhân (ví dụ: trong\nphòng phẫu thuật hoặc khoa cấp cứu), hoặc với thuốc cản quang đường uống, trực tràng hoặc tiêm trong chẩn\nđoán hình ảnh can thiệp hoặc chẩn đoán hình ảnh khi thuốc là một phần của quy trình.\n\nĐể tạo điều kiện thuận lợi cho việc xem xét tính phù hợp, những người thực hiện việc xem xét cần được tiếp cận\nhồ sơ thuốc của bệnh nhân cũng như thông tin lâm sàng có liên quan đến quá trình xem xét; ví dụ, thông tin liên\nquan đến chức năng thận hoặc gan của bệnh nhân khi thuốc có thể ảnh hưởng hoặc bị ảnh hưởng bởi các cơ quan\nđó. Thông tin này rất cần thiết cho việc xem xét tính phù hợp. Khi các chương trình máy tính được sử dụng để\nkiểm tra chéo các tương tác thuốc-thuốc và dị ứng thuốc, các chương trình phải hiện hành và được cập nhật theo\nkhuyến nghị của nhà sản xuất chương trình. Ngoài ra, khi sử dụng tài liệu tham khảo dạng in, các phiên bản mới\nnhất của tài liệu sẽ được sử dụn.","m":[],"sec":"Chuẩn bị và phân phối"},{"c":"MMU.05.03","ch":"MMU","t":"Một hệ thống được sử dụng để phân phối thuốc an toàn với liều lượng phù hợp cho đúng bệnh nhân vào đúng thời điểm.","p":"Việc sử dụng thuốc ngày càng trở nên phức tạp và lỗi dùng thuốc là nguyên nhân chính gây ra tác hại có thể phòng\nngừa cho bệnh nhân. Một hệ thống thống nhất để phân phối và phân phối thuốc ở dạng sẵn sàng sử dụng nhất\ncó thể giúp giảm nguy cơ xảy ra lỗi dùng thuốc.\n\nBệnh viện phân phối thuốc ở dạng sẵn sàng sử dụng nhất có thể để giảm thiểu khả năng xảy ra lỗi trong quá trình\nphân phối và sử dụng. Vấn đề về dạng sẵn sàng sử dụng nhất trở nên quan trọng trong các tình huống khẩn cấp\nkhi việc sử dụng thuốc ngay lập tức có thể cứu sống bệnh nhân (ví dụ, trong quá trình hồi sức). Nhà thuốc trung\ntâm và các điểm phân phối thuốc khác trên khắp bệnh viện sử dụng cùng một hệ thống. Hệ thống hỗ trợ việc\nphân phối thuốc chính xác và kịp thời.\n\nThực hành phân phối và lưu trữ hồ sơ phải bao gồm các chiến lược chống chuyển hướng. Khi thuốc được\nchuẩn bị bởi một người khác với người dùng thuốc (ví dụ, khi thuốc được y tá phẫu thuật chuẩn bị để dùng\ncho bệnh nhân trong quá trình phẫu thuật tại phòng phẫu thuật của bác sĩ phẫu thuật), nguy cơ xảy ra lỗi\ndùng thuốc sẽ tăng lên. Do đó, khi thuốc được lấy ra khỏi bao bì gốc hoặc được chuẩn bị và phân phối ở\ndạng/hộp đựng khác—và không được dùng ngay lập tức (ví dụ, insulin, thuốc được chuẩn bị để sử dụng\ntrong quá trình phẫu thuật tại phòng phẫu thuật, thuốc nhỏ giọt liên tục, dinh dưỡng hoàn toàn cho cha mẹ\n[TPN])—thuốc phải được dán nhãn ghi tên thuốc, liều lượng/nồng độ thuốc, ngày chuẩn bị, ngày hết hạn và\nhai mã định danh bệnh nhân. Khi thuốc được chuẩn bị để sử dụng trong quá trình phẫu thuật tại phòng phẫu\nthuật và các phần chưa sử dụng được loại bỏ ngay sau khi phẫu thuật, tên bệnh nhân và ngày hết hạn có thể\nkhông cần thiết.","m":[],"sec":"Chuẩn bị và phân phối"},{"c":"MMU.06.00","ch":"MMU","t":"Việc quản lý thuốc được thực hiện an toàn bởi những cá nhân có trình độ.","p":"Mỗi bệnh viện có trách nhiệm xác định những cá nhân có đủ kiến thức và kinh nghiệm cần thiết và cũng được\ncấp phép, chứng nhận, luật hoặc quy định để quản lý thuốc. Việc quản lý thuốc để điều trị cho bệnh nhân đòi\nhỏi kiến thức và kinh nghiệm cụ thể. Bệnh viện có thể đặt ra giới hạn về việc quản lý thuốc của một cá nhân,\nchẳng hạn như đối với các chất được kiểm soát hoặc thuốc phóng xạ và thuốc đang nghiên cứu. Trong các tình\nhuống khẩn cấp, bệnh viện xác định bất kỳ cá nhân nào được phép quản lý thuốc.\n\nHồ sơ bệnh án của mỗi bệnh nhân nhận thuốc có chứa danh sách các loại thuốc được kê đơn hoặc yêu cầu cho bệnh nhân\nvà liều lượng cũng như thời gian dùng thuốc. Bao gồm cả thuốc được dùng “khi cần thiết”\n\nNếu thông tin này được ghi trên một mẫu đơn thuốc riêng, mẫu đơn đó sẽ được chèn vào hồ sơ y tế của\nbệnh nhân khi xuất viện hoặc chuyển viện.\n\nBệnh viện xác định quy trình xác minh được sử dụng trong việc cấp phát thuốc. Khi thuốc được chuẩn bị và phân\nphối tại đơn vị chăm sóc bệnh nhân, quy trình đánh giá tính phù hợp được mô tả trong MMU.05.02 cũng phải\nđược thực hiện bởi một cá nhân đủ điều kiện.\n\nĐể hỗ trợ bệnh nhân tham gia vào mọi khía cạnh chăm sóc và điều trị y tế, bệnh nhân được thông báo về loại thuốc\nhọ đang được dùng và được cung cấp cơ hội để đặt câu hỏi về các loại thuốc. Thuốc được cấp cho bệnh nhân kịp\nthời và được ghi chú trong hồ sơ y tế của bệnh nhân.","m":[],"sec":"Quản lý"},{"c":"MMU.06.01","ch":"MMU","t":"Các chính sách và thủ tục quản lý thuốc do bệnh nhân hoặc gia đình mang vào bệnh viện, thuốc được kê đơn để bệnh nhân tự dùng và thuốc được mang vào bệnh viện dưới dạng mẫu.","p":"Thuốc không được phân phối từ nhà thuốc bệnh viện, chẳng hạn như thuốc do bệnh nhân hoặc gia đình mang\nđến hoặc mẫu thuốc, yêu cầu các quy trình đặc biệt để dán nhãn, lưu trữ và kiểm soát việc sử dụng. Bệnh viện có\nquy trình xác định danh tính, tính an toàn và bất kỳ chống chỉ định tương đối nào khác khi sử dụng thuốc do bệnh\nnhân cung cấp hoặc thuốc mẫu. Bệnh viện phải nhận thức được các xu hướng khu vực hiện tại liên quan đến\ntình trạng quản lý và sử dụng thuốc phổ biến (MMU) của thuốc giả và các đợt thu hồi tích cực đối với thuốc và các\nthành phần dược phẩm hoạt tính liên quan.\n\nThuốc do bệnh nhân hoặc gia đình bệnh nhân mang vào bệnh viện hoặc được kê đơn trong bệnh viện để\ntự dùng được bác sĩ của bệnh nhân biết và ghi chú trong hồ sơ y tế của bệnh nhân.\n\nBệnh viện thực hiện quy trình để bệnh nhân tự dùng thuốc, gia đình dùng thuốc và quản lý, sử dụng và\nghi chép thuốc hoặc mẫu thuốc.","m":[],"sec":"Quản lý"},{"c":"MMU.07.00","ch":"MMU","t":"Bệnh viện theo dõi và ứng phó với các sự kiện thuốc có hại thực tế hoặc tiềm ẩn và các phản ứng thuốc có hại.","p":"Mục đích của việc theo dõi là đánh giá tác dụng của thuốc đối với các triệu chứng hoặc bệnh tật của bệnh nhân,\ncũng như công thức máu, chức năng thận, chức năng gan và các tác dụng vật lý và sinh học liên quan đến thuốc\nkhác; đánh giá bệnh nhân về các tác dụng phụ; và phản ứng với các tác dụng đã ghi nhận một cách phù hợp. Định\nnghĩa về các biến cố thuốc có hại và phản ứng thuốc có hại được tham chiếu trong chính sách của JCI đối với các\nbiến cố quan trọng và như sau:\n\nBiến cố thuốc có hại: chấn thương do can thiệp y tế liên quan đến thuốc, bao gồm tác hại do phản ứng thuốc có\nhại hoặc lỗi dùng thuốc.\n\nPhản ứng thuốc có hại: phản ứng với một sản phẩm thuốc có hại và không mong muốn, xảy ra ở liều thường\ndùng cho người để phòng ngừa, chẩn đoán hoặc điều trị bệnh hoặc để phục hồi, điều chỉnh hoặc thay đổi chức\nnăng sinh lý hoặc tâm lý.\n\nBệnh nhân, bác sĩ, y tá và các chuyên gia chăm sóc sức khỏe khác cùng nhau theo dõi bệnh nhân dùng thuốc. Dựa\ntrên việc theo dõi, liều lượng hoặc loại thuốc có thể được điều chỉnh khi cần thiết. Cần theo dõi chặt chẽ phản\nứng của bệnh nhân đối với liều đầu tiên của một loại thuốc mới đối với bệnh nhân. Việc theo dõi như vậy nhằm\nmục đích xác định phản ứng điều trị dự kiến cũng như phản ứng dị ứng, tương tác thuốc-thuốc không lường\ntrước được hoặc thay đổi trạng thái cân bằng của bệnh nhân làm tăng nguy cơ té ngã, trong số những trường hợp\nkhác.\n\nTheo dõi tác dụng của thuốc bao gồm quan sát, phản ứng kịp thời và ghi lại bất kỳ tác dụng phụ nào. Bệnh viện\ncó chính sách xác định tất cả các tác dụng phụ cần ghi lại và những tác dụng phụ phải báo cáo. Bệnh viện thiết\nlập cơ chế báo cáo các sự kiện bất lợi khi cần thiết và khung thời gian báo cáo.","m":[],"sec":"Giám sát"},{"c":"MMU.07.01","ch":"MMU","t":"Bệnh viện triển khai quy trình xác định, báo cáo, quản lý và theo dõi tất cả các lỗi dùng thuốc và các sự kiện suýt xảy ra (hoặc các cuộc gọi suýt xảy ra).","p":"JCI định nghĩa lỗi dùng thuốc là “một sự kiện có thể phòng ngừa được có thể gây ra hoặc dẫn đến việc sử\ndụng thuốc không phù hợp hoặc gây hại cho bệnh nhân hoặc cư dân trong khi thuốc nằm trong tầm kiểm\nsoát của chuyên gia chăm sóc sức khỏe, bệnh nhân, cư dân hoặc người tiêu dùng. Các sự kiện như vậy có\nthể liên quan đến hoạt động chuyên môn; sản phẩm chăm sóc sức khỏe; quy trình và hệ thống, bao gồm kê\nđơn; giao tiếp đơn thuốc; dán nhãn sản phẩm, đóng gói và danh pháp; pha chế; phân phối; quản lý; giáo\ndục; giám sát; và sử dụng”.\n\nCác quy trình được phát triển và triển khai nhằm mục đích xác định, theo dõi, lập xu hướng, phân tích và\nbáo cáo lỗi và các sự kiện bất lợi, sự cố suýt xảy ra và các biến chứng. Ngoài ra, để chủ động tìm hiểu nơi\ncác hệ thống có thể dễ bị các sự kiện bất lợi, chương trình thu thập dữ liệu và thông tin về các sự kiện và\nbiến chứng “suýt xảy ra”—một biến thể của quy trình không ảnh hưởng đến kết quả—và đánh giá chúng\nđể ngăn ngừa sự cố bất lợi thực sự xảy ra. Dữ liệu đo lường thường quy, cũng như dữ liệu từ các đánh\ngiá chuyên sâu, góp phần vào sự hiểu biết này về nơi cần lập kế hoạch cải thiện và mức độ ưu tiên nào cần\ndành cho việc cải thiện.\n\nBệnh viện chịu trách nhiệm lập kế hoạch và thực hiện các thay đổi để cải thiện dựa trên phân tích các lỗi\nhoặc sự kiện bất lợi, sự cố suýt xảy ra và các biến chứng. Quy trình này bao gồm việc xác định lỗi dùng\nthuốc và sự cố suýt xảy ra, sử dụng định dạng chuẩn để báo cáo và đào tạo nhân viên về quy trình và tầm\nquan trọng của việc báo cáo. Bệnh viện thiết lập định nghĩa về sự cố suýt xảy ra và các loại sự kiện cần báo\ncáo, cũng như các biến chứng tiềm ẩn liên quan đến việc chăm sóc, điều trị và các dịch vụ được cung cấp.\n\nCác tổ chức chăm sóc sức khỏe thúc đẩy văn hóa an toàn tập trung vào các hoạt động quản lý thuốc an\ntoàn, bao gồm thúc đẩy báo cáo lỗi mà không sợ bị trả thù. Việc ghi chép và báo cáo lỗi là những bước đầu\ntiên để rút kinh nghiệm từ lỗi và tránh tái diễn. Thông tin phải được ghi chép và báo cáo, và dữ liệu phải\nđược phân tích để xác định các cơ hội cải thiện. Nếu không thực hiện quy trình bao gồm việc sử dụng dữ\nliệu để cải thiện các hoạt động an toàn, các bệnh viện sẽ phải đối mặt với những rào cản đầy thách thức\ntrong nỗ lực cải thiện an toàn của mình. Ví dụ, một cuộc khảo sát ở Châu Âu cho thấy kết quả sau:\n\n•\nTám phần trăm bệnh viện không ghi lại lỗi dùng thuốc trong cơ sở dữ liệu và chỉ có 13% bệnh\nviện công khai dữ liệu lỗi dùng thuốc cho công chúng. Tuy nhiên, 33% bệnh viện không có cơ\nsở dữ liệu lỗi dùng thuốc để chia sẻ các cải tiến liên tục.\n•\nMười bốn phần trăm bệnh viện không theo dõi lỗi dùng thuốc thường xuyên và 71% bệnh viện\ntheo dõi lỗi dùng thuốc tập trung (hầu hết sử dụng dữ liệu lỗi theo dõi như một phân tích\nnguyên nhân gốc rễ để giải quyết sự cố cũng như được điều tra tại các cuộc họp chất lượng\nthường xuyên). Tuy nhiên, 23% bệnh viện không sử dụng hệ thống đó thường xuyên.\n\nQuy trình báo cáo là một phần của chương trình chất lượng và an toàn bệnh nhân của bệnh viện. Các\nbáo cáo được chuyển đến một hoặc nhiều cá nhân có trách nhiệm hành động. Chương trình tập trung\nvào việc ngăn ngừa lỗi dùng thuốc thông qua việc hiểu các loại lỗi xảy ra trong bệnh viện và trong các tổ\nchức khác và lý do tại sao xảy ra tình trạng suýt xảy ra. Cải tiến trong quy trình dùng thuốc và đào tạo\nnhân viên được sử dụng để ngăn ngừa lỗi trong tương lai. Nhà thuốc tham gia vào chương trình đào\ntạo nhân viên như vậy. Ngoài ra, các chiến lược cải thiện giao tiếp giữa các chuyên gia tham gia kê đơn,\nxác nhận, chuẩn bị, quản lý và phân phối thuốc là chìa khóa để giảm thiểu lỗi dùng thuốc.","m":[],"sec":"Giám sát"},{"c":"MOI.01.00","ch":"MOI","t":"Bệnh viện lập kế hoạch quản lý thông tin và lựa chọn các quy trình để đáp ứng nhu cầu của những người yêu cầu dữ liệu và thông tin.","p":"Thông tin được tạo ra và sử dụng trong quá trình chăm sóc, điều trị và dịch vụ bệnh nhân và để quản lý một\nbệnh viện an toàn và hiệu quả.\n\nKhả năng thu thập và cung cấp thông tin đòi hỏi phải có kế hoạch hiệu quả. Kế hoạch quản lý thông tin có\nthể bao gồm những nội dung sau:\n• Sứ mệnh của bệnh viện\n• Dịch vụ được cung cấp\n• Tài nguyên\n• Tiếp cận công nghệ giá cả phải chăng\n• Đánh giá khả năng sử dụng và khả năng tương tác\n• Hỗ trợ giao tiếp hiệu quả giữa những người chăm sóc\n\nKế hoạch kết hợp thông tin đầu vào từ nhiều nguồn khác nhau sử dụng dữ liệu và thông tin, bao gồm\nnhững nội dung sau:\n• Các bác sĩ chăm sóc sức khỏe và các nhân viên khác cung cấp dịch vụ lâm sàng\n• Lãnh đạo bệnh viện và lãnh đạo khoa/dịch vụ\n\n(\nI)\n\n• Các cá nhân, dịch vụ và cơ quan bên ngoài bệnh viện sử dụng dữ liệu hoặc thông tin về quy trình hoạt động và chăm sóc\ncủa bệnh viện\n\nNhu cầu thông tin của các nguồn này phải cung cấp thông tin cho các chiến lược quản lý thông tin của bệnh viện và khả\nnăng thực hiện các chiến lược đó. Các chiến lược phải đáp ứng nhu cầu của bệnh viện dựa trên quy mô bệnh viện, tính\nphức tạp của các dịch vụ, sự sẵn có của đội ngũ nhân viên được đào tạo và các nguồn nhân lực và kỹ thuật khác.\n\nCác quy trình thông tin rất toàn diện và bao gồm tất cả các khoa và dịch vụ của bệnh viện. Việc lập kế hoạch quản lý\nthông tin không yêu cầu một chương trình thông tin chính thức bằng văn bản nhưng yêu cầu bằng chứng về một phương\npháp tiếp cận có kế hoạch xác định nhu cầu thông tin và quy trình của bệnh viện để đáp ứng các nhu cầu đó.\n\nCác yếu tố đo lường được của MOI.01.00\n1. Bệnh viện lựa chọn các quy trình để đáp ứng nhu cầu thông tin của những đối tượng sau:\n• Những người cung cấp dịch vụ lâm sàng\n• Các nhà lãnh đạo bệnh viện và các nhà lãnh đạo khoa/dịch vụ (Xem thêm GLD.03.02, ME 1 và 2)\n• Các cá nhân, dịch vụ và cơ quan bên ngoài bệnh viện (Xem thêm GLD.03.01, ME 2)\n• Bệnh nhân truy cập dữ liệu cá nhân\n2. Các quy trình được triển khai phù hợp với quy mô bệnh viện, tính phức tạp của các dịch vụ, tính sẵn có của\nnhân viên được đào tạo, nguồn lực kỹ thuật và các nguồn lực khác.\n3. Việc lập kế hoạch và thiết kế các quy trình quản lý thông tin của bệnh viện bao gồm những điều sau:\n• Sứ mệnh của bệnh viện\n• Các dịch vụ được cung cấp\n• Nguồn lực\n• Tiếp cận công nghệ giá cả phải chăng\n• Đánh giá khả năng sử dụng và khả năng tương tác\n• Hỗ trợ giao tiếp hiệu quả giữa những người chăm sóc","m":[],"sec":"Lập kế hoạch quản lý thông tin"},{"c":"MOI.01.01","ch":"MOI","t":"Bệnh viện duy trì tính bảo mật, an ninh, riêng tư và toàn vẹn của dữ liệu và thông tin thông qua các quy trình quản lý và kiểm soát quyền truy cập.","p":"Bệnh viện thiết lập các quy trình để bảo vệ thông tin nhạy cảm của bệnh nhân và ngăn chặn việc truy cập trái\nphép vào dữ liệu, điều này có thể gây ra hậu quả lớn hơn.\n\nCân bằng giữa chia sẻ dữ liệu và bảo mật dữ liệu được giải quyết. Bệnh viện phải tuân theo các quy trình đã\nthiết lập để di chuyển an toàn thông tin hồ sơ y tế của bệnh nhân và phát hành thông tin.\n\nCho dù bệnh viện sử dụng hệ thống thông tin giấy và/hoặc điện tử, bệnh viện đều thực hiện các biện pháp để\nbảo mật và bảo vệ dữ liệu và thông tin mọi lúc. Dữ liệu và thông tin bao gồm:\n• Hồ sơ bệnh án của bệnh nhân\n• Dữ liệu từ thiết bị và dụng cụ y tế\n• Dữ liệu nghiên cứu\n• Dữ liệu chất lượng\n• Dữ liệu thanh toán\n• Dữ liệu nguồn nhân lực\n• Các nguồn áp dụng khác\n\nCác biện pháp bảo mật bao gồm các quy trình quản lý và kiểm soát quyền truy cập. Bệnh viện xác định ai\nđược phép truy cập hồ sơ y tế và triển khai các quy trình để chỉ định quyền cho người dùng được ủy quyền\ntheo mức độ truy cập của họ.\n\n(\nI)\n\nNgười dùng được ủy quyền có thể nhập, sửa đổi và xóa thông tin hoặc có thể có quyền truy cập chỉ đọc hoặc\nhạn chế vào một số hệ thống hoặc mô-đun. Mức độ truy cập có thể xác định ai có thể nhập vào hồ sơ bệnh\nán, ai có thể nhập lệnh của bệnh nhân, ai có thể truy cập vào các trường hợp bệnh nhân có tính bảo mật cao,\nai có thể truy cập vào dữ liệu cải thiện chất lượng, v.v.\n\nĐối với các bệnh viện có hệ thống thông tin điện tử, việc theo dõi quyền truy cập vào dữ liệu và thông tin của\nbệnh nhân thông qua kiểm toán bảo mật nhật ký truy cập có thể giúp bảo vệ tính bảo mật và an ninh. Bệnh\nviện triển khai các cuộc kiểm toán bảo mật thường xuyên để chủ động theo dõi nhật ký truy cập và xác định lỗ\nhổng hệ thống hoặc vi phạm chính sách bảo mật.\n\nCác bệnh viện sử dụng trợ lý tài liệu hoặc người ghi chép có quy trình để đảm bảo bảo vệ thông tin của bệnh\nnhân, bao gồm đào tạo, năng lực, trách nhiệm công việc đã nêu và phạm vi hoạt động tài liệu được xác định rõ\nràng. Khi sử dụng hồ sơ sức khỏe điện tử, các biện pháp bảo mật bổ sung sẽ được triển khai (ví dụ: thông tin\nxác thực duy nhất chỉ được cấp cho họ).\n\nMức độ truy cập dữ liệu và thông tin của mỗi cá nhân được ủy quyền dựa trên nhu cầu và được xác định bởi\nvai trò và trách nhiệm của người đó. Sinh viên, thực tập sinh, người ghi chép và những người khác, theo quyết\nđịnh của bệnh viện, đều được bao gồm. Một quy trình hiệu quả xác định những điều sau:\n• Ai được phép truy cập dữ liệu và thông tin, bao gồm hồ sơ y tế của bệnh nhân\n• Thông tin mà cá nhân được ủy quyền có quyền truy cập (mức độ truy cập)\n• Quy trình cấp quyền truy cập cho cá nhân được ủy quyền\n• Nghĩa vụ của cá nhân trong việc giữ thông tin bảo mật và an toàn\n• Quy trình duy trì tính toàn vẹn của dữ liệu (độ chính xác, tính nhất quán và tính đầy đủ)\n• Quy trình được thực hiện khi tính bảo mật, an ninh hoặc tính toàn vẹn của dữ liệu bị vi phạm hoặc xâm phạm\n\nKiểm toán bảo mật có thể xác định người dùng hệ thống đã thay đổi, chỉnh sửa hoặc xóa thông tin và có thể\ntheo dõi các thay đổi được thực hiện đối với hồ sơ sức khỏe điện tử. Thông tin này có thể được sử dụng để\nxác thực rằng quyền của người dùng được thiết lập phù hợp theo vai trò hiện tại và xác định quyền của người\ndùng cần phải xóa do thay đổi nhân sự.\n\nNếu bệnh viện đang có kế hoạch chuyển đổi từ hệ thống hồ sơ sức khỏe vật lý sang hệ thống hồ sơ sức khỏe\nđiện tử, cần cân nhắc để đảm bảo an toàn và bảo mật thông tin bệnh nhân. Các yếu tố cần xem xét bao gồm:\n• Khung thời gian chuyển đổi dữ liệu\n• Thông tin nào cần được chuyển đổi\n• Việc hủy dữ liệu không còn cần thiết nữa\n• Thông tin sẽ được chuyển đổi như thế nào (ví dụ: nhập dữ liệu trực tiếp hoặc quét)\n• Nơi nhập dữ liệu diễn ra (ví dụ: tập trung hay phi tập trung)\n\nCác yếu tố đo lường được của MOI.01.01\n1.\nBệnh viện thực hiện các quy trình phù hợp với luật pháp và quy định để đảm bảo tính bảo mật, an toàn và\ntoàn vẹn của dữ liệu và thông tin. (Xem thêm PCC.01.02, ME 1)\n2.\nBệnh viện xác định, bằng văn bản, những người được phép truy cập dữ liệu và thông tin, bao gồm những\nngười được phép nhập dữ liệu vào hồ sơ y tế của bệnh nhân và xác định mức độ truy cập của họ dựa\ntrên vai trò và trách nhiệm của từng cá nhân.\n3.\nBệnh viện có một quy trình để cấp cho những cá nhân được phép quyền truy cập dữ liệu và thông tin theo\nmức độ truy cập của họ.\n4.\nBệnh viện thực hiện các quy trình để đảm bảo rằng dữ liệu và thông tin chỉ được những cá nhân được phép\ntruy cập và theo mức độ truy cập của họ. (Xem thêm ACC.03.00, ME 2)\n5.\nBệnh viện thực hiện các quy trình để đảm bảo rằng chỉ những cá nhân được phép mới được nhập dữ liệu\nvào hồ sơ y tế của bệnh nhân và theo mức độ truy cập của họ.\n6.\nBệnh viện giám sát việc tuân thủ các quy trình và việc phát hành thông tin và hành động khi xảy ra vi phạm.\n\n(\nI)","m":[]},{"c":"MOI.01.02","ch":"MOI","t":"Bệnh viện duy trì tính bảo mật, an ninh, riêng tư và toàn vẹn của dữ liệu và thông tin thông qua các quy trình bảo vệ chống lại mất mát, trộm cắp, hư hỏng, phá hủy, phần mềm tống tiền và các cuộc tấn công mạng khác.","p":"Các lỗ hổng dẫn đến vi phạm thông tin và dữ liệu nhạy cảm có thể nghiêm trọng và lan rộng đối với\nbệnh viện và bệnh nhân mà bệnh viện phục vụ.\n\nBệnh viện đảm bảo rằng hồ sơ sức khỏe, dữ liệu và thông tin khác trên giấy và điện tử được bảo vệ khỏi\nbị mất, trộm cắp, giả mạo, hư hỏng và phá hủy ngoài ý muốn.\n\nCác lỗ hổng gây ra rủi ro bảo mật bao gồm phản hồi email lừa đảo, gửi email không được mã hóa, sử\ndụng sai mật khẩu hoặc đặt nhầm thiết bị công nghệ. Bệnh viện cũng đánh giá các lỗ hổng bảo mật mạng\nbên ngoài/từ xa, bao gồm tin tặc, vi phạm thông tin, phần mềm tống tiền hoặc phần mềm độc hại khác.\n\nĐể bảo vệ dữ liệu và thông tin, bệnh viện triển khai các biện pháp bảo mật dữ liệu tốt nhất và đảm bảo\nlưu trữ hồ sơ y tế, dữ liệu và thông tin an toàn và bảo mật. Ví dụ về các biện pháp và chiến lược bảo\nmật bao gồm nhưng không giới hạn ở những điều sau:\n•\nĐảm bảo phần mềm bảo mật và các bản cập nhật hệ thống là mới nhất\n•\nMã hóa dữ liệu, chẳng hạn như dữ liệu được lưu trữ ở dạng kỹ thuật số\n•\nBảo vệ dữ liệu và thông tin thông qua các chiến lược sao lưu như lưu trữ ngoài trang web và/hoặc dịch vụ sao\nlưu đám mây\n•\nLưu trữ hồ sơ y tế vật lý ở những nơi được bảo vệ khỏi nhiệt, nước, hỏa hoạn, sâu bệnh\n•\nhoặc sự xâm nhập\n•\nLưu trữ hồ sơ y tế đang hoạt động ở những khu vực mà chỉ những bác sĩ được cấp phép mới được tiếp cận\n•\nĐảm bảo rằng các phòng máy chủ và khu vực lưu trữ hồ sơ y tế vật lý được bảo mật và\n•\nchỉ những cá nhân được cấp phép mới được tiếp cận\n•\nĐảm bảo rằng các phòng máy chủ và khu vực lưu trữ hồ sơ y tế vật lý ở mức nhiệt độ và độ ẩm thích hợp để\nbảo vệ máy chủ/hồ sơ\n•\nĐảm bảo rằng các phòng máy chủ và khu vực lưu trữ hồ sơ y tế vật lý được bảo vệ khỏi nguy cơ hỏa hoạn\n•\nTiến hành và lập tài liệu đánh giá rủi ro bảo mật thông tin đang diễn ra, ít nhất là hàng năm\n\nĐánh giá rủi ro xem xét việc xem xét các quy trình và dịch vụ mới và đã lên kế hoạch có thể gây ra rủi\nro cho dữ liệu và thông tin. Rủi ro được ưu tiên từ đánh giá rủi ro và các cải tiến được xác định và\ntriển khai để giải quyết các rủi ro. Các cải tiến được theo dõi để đảm bảo rằng các rủi ro được ngăn\nngừa hoặc loại bỏ.\n\nNhững tiến bộ về công nghệ tạo ra nhiều cơ hội hơn cho thông tin điện tử bị vi phạm. Bệnh viện\nđảm bảo rằng nhân viên được đào tạo, ít nhất là hàng năm, về các chủ đề sau:\n•\nQuy trình và hành vi đăng nhập (ví dụ: không chia sẻ thông tin xác thực)\n•\nĐào tạo về phần mềm độc hại\n•\nBáo cáo lừa đảo qua email\n\n(\nI)\n\nCác yếu tố đo lường được của MOI.01.02\n1.\nBệnh viện tiến hành và lập hồ sơ đánh giá rủi ro bảo mật thông tin hàng năm trên toàn bộ tổ chức và các\nrủi ro bảo mật dữ liệu được xác định và ưu tiên từ đánh giá rủi ro.\n2.\nDữ liệu và thông tin được lưu trữ theo cách bảo vệ chống lại mất mát, trộm cắp, hư hỏng, phá hủy, phần\nmềm tống tiền và các cuộc tấn công mạng khác.\n3.\nBệnh viện triển khai các biện pháp bảo mật dữ liệu tốt nhất để bảo vệ và bảo mật dữ liệu và thông tin.\n(Xem thêm PCC.01.02, ME 1; HCT.01.01, ME 1 và 2)\n4.\nBệnh viện xác định mục tiêu, triển khai các cải tiến để giải quyết các rủi ro bảo mật dữ liệu và theo dõi\ndữ liệu cải tiến để đảm bảo giảm thiểu hoặc loại bỏ các rủi ro.\n5.\nBệnh viện thiết lập chính sách bằng văn bản với các thủ tục cần tuân theo trong trường hợp xảy ra cuộc\ntấn công mạng thành công","m":[]},{"c":"MOI.01.03","ch":"MOI","t":"Bệnh viện xác định thời gian lưu giữ hồ sơ y tế, dữ liệu và thông tin khác của bệnh nhân.","p":"Bệnh viện xác định thời gian lưu giữ hồ sơ y tế, dữ liệu và thông tin khác được lưu giữ trong thời gian đủ để tuân thủ\nluật pháp và quy định và hỗ trợ chăm sóc bệnh nhân, quản lý, lập hồ sơ pháp lý, nghiên cứu và giáo dục khi áp dụng.\n\nQuy trình lưu giữ hồ sơ y tế, dữ liệu và thông tin khác, bao gồm tin nhắn văn bản và email có chứa thông tin về hồ sơ y\ntế, phù hợp với các chính sách và quy trình của bệnh viện nhằm duy trì tính bảo mật và an toàn của thông tin đó. Sau\nthời gian lưu giữ, hồ sơ y tế, dữ liệu và thông tin khác của bệnh nhân sẽ bị hủy theo cách không làm ảnh hưởng đến\ntính bảo mật và an toàn.\n\nCác yếu tố đo lường được của MOI.01.03\n1.\nBệnh viện xác định thời gian lưu giữ hồ sơ y tế của bệnh nhân và các dữ liệu, thông tin khác\nvà tuân thủ luật pháp và quy định.\n2.\nQuy trình lưu giữ đảm bảo tính bảo mật và an toàn như mong đợi.\n3.\nHồ sơ bệnh án, dữ liệu và thông tin khác của bệnh nhân bị hủy hoặc xóa theo cách không làm\nảnh hưởng đến tính bảo mật và an toàn.","m":[]},{"c":"MOI.01.04","ch":"MOI","t":"Nhân viên lâm sàng, người ra quyết định và các nhân viên khác được đào tạo và giáo dục về hệ thống thông tin, bảo mật thông tin và các nguyên tắc sử dụng và quản lý thông tin.","p":"Các cá nhân trong bệnh viện tạo ra, thu thập, nhập, xem xét, phân tích và sử dụng dữ liệu và thông tin\nđược đào tạo và giáo dục để thực hiện hiệu quả các chức năng công việc của họ.\n\nGiáo dục và đào tạo này cho phép những cá nhân này thực hiện những điều sau:\n• Sử dụng các hệ thống thông tin, chẳng hạn như hệ thống hồ sơ sức khỏe điện tử, để thực hiện trách nhiệm\ncông việc của họ một cách hiệu quả và an toàn.\n• Tuân thủ các chính sách và quy trình để đảm bảo an ninh và bảo mật dữ liệu và thông tin.\n• Triển khai các chiến thuật và chiến lược để quản lý dữ liệu, thông tin và tài liệu trong thời gian ngừng hoạt\nđộng theo kế hoạch và không theo kế hoạch.\n• Sử dụng dữ liệu và thông tin để hỗ trợ ra quyết định.\n• Giáo dục và hỗ trợ bệnh nhân và gia đình về việc tham gia vào các quy trình chăm sóc.\n\n(\nI)\n\n•\nSử dụng các biện pháp để đánh giá và cải thiện quy trình chăm sóc và làm việc.\n\nCác bệnh viện có hệ thống hồ sơ sức khỏe điện tử đảm bảo rằng nhân viên cần truy cập, xem xét và/hoặc ghi vào hồ sơ\nbệnh án của bệnh nhân sẽ được giáo dục, đào tạo liên tục và đánh giá để sử dụng hệ thống một cách hiệu quả.\n\nVi phạm an ninh mạng có thể gây ra các vấn đề về an toàn cho bệnh nhân và gây tốn kém cho hệ thống bệnh viện. Các bệnh\nviện cũng đảm bảo rằng nhân viên được đào tạo về an ninh mạng liên quan đến trách nhiệm và mô tả công việc của họ để\nduy trì tính bảo mật của thông tin.\n\nQuy trình quản lý thông tin giúp kết hợp thông tin từ nhiều nguồn khác nhau và tạo báo cáo để hỗ trợ ra quyết định bằng\ndữ liệu theo chiều dọc và so sánh. Sự kết hợp giữa thông tin lâm sàng và thông tin quản lý giúp các nhà lãnh đạo khoa/dịch\nvụ lập kế hoạch một cách hợp tác.\n\nCó thể sử dụng nhiều phương pháp khác nhau để đào tạo liên tục có liên quan đến nhu cầu của nhân viên và cung cấp\nhướng dẫn hữu ích về cách sử dụng hệ thống. Ví dụ bao gồm những nội dung sau:\n•\n“Mẹo và thủ thuật”\n•\nHướng dẫn tham khảo nhanh\n•\nCác mô-đun giáo dục ngắn\n•\nBản tin (được đăng hoặc gửi qua email)\n\nCác chủ đề giáo dục và đào tạo về an ninh mạng có thể bao gồm những nội dung sau:\n•\nBảo vệ mật khẩu\n•\nPhần mềm độc hại và phần mềm tống tiền\n•\nLừa đảo qua email\n•\nQuản lý thiết bị\n•\nBảo vệ dữ liệu nhạy cảm\n•\nCập nhật thiết bị\n•\nBáo cáo hoạt động đáng ngờ\n\nCác yếu tố đo lường được của MOI.01.04\n1.\nNhân viên lâm sàng, người ra quyết định và những người khác được cung cấp giáo dục và đào tạo\nvề hệ thống thông tin, bảo mật thông tin và các nguyên tắc sử dụng và quản lý thông tin, phù hợp\nvới vai trò và trách nhiệm của họ.\n2.\nNhân viên sử dụng hệ thống hồ sơ sức khỏe điện tử được giáo dục, đào tạo liên tục và đánh giá\nđể đảm bảo rằng họ có thể sử dụng hệ thống một cách hiệu quả và hiệu suất để thực hiện trách\nnhiệm công việc của mình.\n3.\nNhân viên được giáo dục và đào tạo liên tục, hàng năm liên quan đến an ninh mạng dựa trên vai\ntrò và trách nhiệm của họ.\n4.\nDữ liệu và thông tin lâm sàng và quản lý được tích hợp khi cần thiết để hỗ trợ việc ra quyết định.","m":[]},{"c":"MOI.02.00","ch":"MOI","t":"Các tài liệu, bao gồm các chính sách, thủ tục và chương trình, được quản lý theo cách thống nhất và nhất quán.","p":"Các chính sách và thủ tục nhằm mục đích cung cấp kiến thức thống nhất về các chức năng lâm sàng và phi lâm sàng của\ntổ chức.\nMột tài liệu viết hướng dẫn cách thức tất cả các chính sách, thủ tục và chương trình trong bệnh viện sẽ được phát triển\nvà kiểm soát.\n\n(\nI)\n\nCó thể xác định những thay đổi đối với chính sách, quy trình và chương trình là điều cần thiết để duy trì hiệu\nquả, hiệu suất và sự tuân thủ của nhân viên. Các phương pháp xác định những thay đổi có thể bao gồm những\nđiều sau:\n•\nĐánh giá và cập nhật thường xuyên dựa trên lịch trình do bệnh viện thiết lập\n•\nTheo dõi việc tuân thủ để đánh giá các lĩnh vực cần cải thiện hoặc khoảng cách trong hiệu suất\n•\nXem xét các nghiên cứu hiện tại và có liên quan để đánh giá những thay đổi trong ngành\n•\nCơ hội phản hồi của nhân viên, bao gồm các cuộc khảo sát, hộp góp ý hoặc các buổi phản hồi\n•\nCác kênh truyền thông để thông báo cho nhân viên về những thay đổi chính sách, bao gồm thông báo\nqua email, bản tin và các cuộc họp nhóm\n•\nGiáo dục và đào tạo nhân viên\n•\nBáo cáo sự cố\n\nCác yếu tố đo lường được của MOI.02.00\n1.\nCó một tài liệu hướng dẫn bằng văn bản xác định các yêu cầu để xem xét các chính sách và thủ tục, bao\ngồm:\n• Xem xét và phê duyệt tất cả các tài liệu bởi một người được ủy quyền trước khi phát hành\n• Tần suất xem xét và tiếp tục phê duyệt các tài liệu\n• Các biện pháp kiểm soát để đảm bảo rằng chỉ có các phiên bản tài liệu hiện tại, có liên quan mới có\nsẵn\n• Phương pháp xác định các thay đổi\n2.\nCó một tài liệu hướng dẫn bằng văn bản xác định các yêu cầu để quản lý các chính sách và thủ tục, bao\ngồm:\n• Duy trì danh tính và tính dễ đọc\n• Quản lý các tài liệu có nguồn gốc bên ngoài bệnh viện\n• Lưu giữ các tài liệu lỗi thời trong thời gian theo yêu cầu của luật pháp và quy định trong khi đảm bảo\nrằng chúng không được sử dụng\n• Theo dõi tất cả các tài liệu đang lưu hành (ví dụ: được xác định theo tiêu đề, ngày phát hành, phiên\nbản và/hoặc ngày sửa đổi hiện tại, số trang và người đã ủy quyền và/hoặc xem xét tài liệu)\n3.\nCó các định dạng chuẩn cho tất cả các tài liệu tương tự (ví dụ: tất cả các chính sách).\n4.\nCác yêu cầu của tài liệu hướng dẫn được thực hiện và thể hiện rõ trong các chính sách, thủ tục và\nchương trình có trong toàn bệnh viện.","m":[],"sec":"Sử dụng thông tin chuẩn hóa"},{"c":"MOI.02.01","ch":"MOI","t":"Các nhà lãnh đạo xem xét, phê duyệt và quản lý việc thực hiện các chính sách và thủ tục hướng dẫn và hỗ trợ việc chăm sóc và dịch vụ cho bệnh nhân.","p":"Trong suốt các tiêu chuẩn công nhận có trong sổ tay này, các chính sách, quy trình, kế hoạch và các tài\nliệu viết khác là bắt buộc (được ghi chú bằng biểu tượng D), vì chúng làm giảm sự thay đổi trong quy\ntrình và giảm rủi ro vốn có trong các quy trình nhằm cải thiện chất lượng và an toàn cho bệnh nhân.\n\nCó một quy trình để đảm bảo rằng các thành viên nhân viên đã đọc và quen thuộc với các chính sách, quy\ntrình và kế hoạch liên quan đến công việc của họ. Quy trình này có thể là một phần trong quá trình định\nhướng của các thành viên nhân viên về phòng ban và trách nhiệm của họ hoặc có thể là một phần của các\nbuổi đào tạo đặc biệt trên toàn nhóm hoặc toàn bệnh viện. Khi một chính sách, quy trình hoặc kế hoạch\ncó liên quan đến nhiệm vụ của một cá nhân, các hành động dự định được mô tả trong tài liệu sẽ thể\nhiện rõ trong các hành động của cá nhân đó.\n\n(\nI)\n\nCác yếu tố đo lường được của MOI.02.01\n1.\nCác chính sách, thủ tục và kế hoạch bắt buộc đều có sẵn và nhân viên hiểu cách truy cập các tài\nliệu liên quan đến trách nhiệm của họ.\n2.\nNhân viên được đào tạo và hiểu các tài liệu liên quan đến trách nhiệm của họ.\n3.\nCác yêu cầu của chính sách, thủ tục và kế hoạch được thực hiện đầy đủ và thể hiện rõ trong\nhành động của từng nhân viên.\n4.\nViệc thực hiện các chính sách, thủ tục và kế hoạch được giám sát và thông tin hỗ trợ việc thực\nhiện đầy đủ.","m":[]},{"c":"MOI.02.02","ch":"MOI","t":"Bệnh viện sử dụng các mã chẩn đoán và quy trình chuẩn hóa và đảm bảo sử dụng thống nhất các ký hiệu và chữ viết tắt đã được phê duyệt trên toàn bệnh viện.","p":"Chuẩn hóa mã và sử dụng thống nhất các ký hiệu và chữ viết tắt giúp ngăn ngừa sự hiểu lầm và các lỗi tiềm ẩn\ntrong quá trình chăm sóc bệnh nhân, đồng thời hỗ trợ tổng hợp và phân tích dữ liệu.\n\nViết tắt có thể gây ra vấn đề và thậm chí nguy hiểm, đặc biệt là trong bối cảnh kê đơn thuốc. Khi được phép sử\ndụng chữ viết tắt trong bệnh viện, các quy trình được triển khai để ngăn ngừa hoặc giảm thiểu rủi ro đối với sự\nan toàn của bệnh nhân. Không sử dụng chữ viết tắt trong các tài liệu có rủi ro cao, dành riêng cho bệnh nhân, vốn\nrất quan trọng đối với tính liên tục của\nviệc chăm sóc, bao gồm:\n• Tài liệu đồng ý có thông tin\n• Tài liệu về quyền của bệnh nhân\n• Hướng dẫn xuất viện\n• Tóm tắt xuất viện\n\nBệnh nhân và gia đình có thể không hiểu các chữ viết tắt được bệnh viện chấp thuận. Với các bản tóm tắt xuất\nviện, có nguy cơ về sự an toàn của bệnh nhân khi sử dụng các chữ viết tắt nếu nhà cung cấp từ một tổ chức khác\nkhông sử dụng cùng một danh sách. Viết tắt thường được sử dụng trong các báo cáo về kết quả xét nghiệm chẩn\nđoán hình ảnh và xét nghiệm trong phòng thí nghiệm.\n\nViệc bệnh viện sử dụng mã chuẩn hóa và sử dụng thống nhất các ký hiệu và chữ viết tắt được chấp thuận phù\nhợp với các tiêu chuẩn hành nghề chuyên môn và tuân thủ luật pháp và quy định của địa phương khi áp dụng.\nNhân viên được đào tạo và hướng dẫn về các nguyên tắc chuẩn hóa và sử dụng thống nhất các mã, ký hiệu và\nchữ viết tắt của bệnh viện.\n\nKhi bệnh viện sử dụng chữ viết tắt, bệnh viện sẽ triển khai quy trình sử dụng thống nhất các chữ viết tắt đã\nđược phê duyệt, chẳng hạn như danh sách tham khảo. Việc sử dụng thống nhất này bao gồm mỗi chữ viết tắt chỉ\ncó một nghĩa. Khi chữ viết tắt có nhiều hơn một nghĩa, việc nhầm lẫn về ý nghĩa của tác giả có thể dẫn đến lỗi y\nkhoa. Ví dụ, chữ viết tắt MS có thể có nghĩa là hẹp van hai lá trong khoa tim mạch; tuy nhiên, trong khoa thần\nkinh, chữ viết tắt MS có thể được sử dụng cho bệnh đa xơ cứng. Ngoài ra, có thể phát sinh nhầm lẫn khi hai chữ\nviết tắt có cùng chữ cái nhưng khác cách viết hoa. Ví dụ, Pt cho bệnh nhân và PT cho\nvật lý trị liệu. Mặc dù việc sử dụng chữ hoa và chữ thường khác nhau giữa hai ví dụ, nhưng về cơ bản chúng là\ncùng một chữ viết tắt có nhiều hơn một nghĩa. Điều quan trọng là việc sử dụng chữ viết tắt phải thống nhất và\nnhất quán trên toàn bệnh viện mà không có sự khác biệt về ý nghĩa giữa các khoa hoặc dịch vụ khác nhau.\n\nKhi một bệnh viện sử dụng các chữ viết tắt, bệnh viện sẽ xây dựng và/hoặc áp dụng danh sách các chữ viết tắt và\nký hiệu không được sử dụng. Ví dụ, Viện Thực hành Thuốc An toàn (ISMP) duy trì danh sách các chữ viết tắt,\nký hiệu và chỉ định liều lượng “không bao giờ được sử dụng khi truyền đạt thông tin y tế”. Các mục trong danh\nsách đã được báo cáo với ISMP là thường xuyên bị hiểu sai và liên quan đến các lỗi dùng thuốc có hại.\n\n(\nI)\n\nNếu cần viết tắt, thì lần xuất hiện đầu tiên của thuật ngữ phải được viết đầy đủ, với chữ viết tắt được liệt kê\ntrong dấu ngoặc đơn.\n\nCác yếu tố đo lường được của MOI.02.02\n1. Bệnh viện sử dụng mã chẩn đoán và mã thủ tục chuẩn hóa.\n2. Bệnh viện thực hiện việc sử dụng thống nhất các ký hiệu đã được phê duyệt và xác định những ký hiệu không\nđược sử dụng.\n3. Nếu bệnh viện cho phép sử dụng chữ viết tắt, bệnh viện đáp ứng các tiêu chí sau:\n• Bệnh viện thực hiện việc sử dụng thống nhất các chữ viết tắt đã được phê duyệt chỉ có một nghĩa.\n• Bệnh viện thực hiện danh sách các chữ viết tắt không được sử dụng.\n• Bệnh viện không sử dụng chữ viết tắt trên giấy đồng ý có thông tin, tài liệu về quyền của bệnh nhân, hướng\ndẫn xuất viện hoặc tóm tắt xuất viện. (Xem thêm PCC.01.01, ME 1)\n• Khi lần đầu tiên sử dụng chữ viết tắt trong tài liệu, trước tiên thuật ngữ đó phải được viết đầy đủ, với chữ viết\ntắt trong ngoặc đơn.\n• Bệnh viện theo dõi việc sử dụng chữ viết tắt và thực hiện hành động để cải thiện quy trình khi cần.","m":[]},{"c":"MOI.02.03","ch":"MOI","t":"Bệnh viện thu thập, phổ biến và truyền tải thông tin sức khỏe kịp thời theo định dạng đáp ứng mong đợi của người dùng và với tần suất mong muốn.","p":"Việc phổ biến dữ liệu và thông tin để đáp ứng nhu cầu của những người trong và ngoài bệnh viện là một khía cạnh\nquan trọng của quản lý thông tin.\nTrong nội bộ, các bác sĩ, lãnh đạo bệnh viện, lãnh đạo khoa/dịch vụ và các nhân viên khác cần dữ liệu và thông tin cụ\nthể kịp thời để họ có thể thực hiện trách nhiệm của mình một cách hiệu quả. Ví dụ, các bác sĩ chăm sóc sức khỏe\nchăm sóc bệnh nhân, bao gồm bác sĩ, y tá, chuyên gia dinh dưỡng, dược sĩ và những người khác, cần có quyền truy\ncập vào thông tin cập nhật và tất cả các phần áp dụng trong hồ sơ y tế của bệnh nhân để cung cấp dịch vụ chăm\nsóc bệnh nhân an toàn và hiệu quả.\nBên ngoài, bệnh viện có thể cung cấp dữ liệu và thông tin cho các cơ quan quản lý (như Bộ Y tế), các bác sĩ chăm sóc\nsức khỏe (như bác sĩ chăm sóc chính của bệnh nhân trong cộng đồng), các dịch vụ và chương trình chăm sóc sức khỏe\n(như phòng xét nghiệm bên ngoài hoặc tổ chức giới thiệu bệnh nhân) và các cá nhân (như bệnh nhân yêu cầu hồ sơ\nbệnh án của họ sau khi xuất viện).\nĐịnh dạng và khung thời gian để phổ biến dữ liệu và thông tin được điều chỉnh để đáp ứng kỳ vọng của người dùng\nđối với cá nhân, dịch vụ hoặc chương trình. Khi dữ liệu và thông tin cần thiết cho việc chăm sóc bệnh nhân, chúng\nđược cung cấp kịp thời để hỗ trợ tính liên tục của việc chăm sóc và sự an toàn của bệnh nhân.\nCác ví dụ về chiến lược phổ biến để đáp ứng kỳ vọng của người dùng bao gồm:\n• Cung cấp dữ liệu và thông tin cụ thể được yêu cầu/bắt buộc\n• Cung cấp báo cáo với tần suất cần thiết cho cá nhân hoặc chương trình\n• Cung cấp dữ liệu và thông tin ở định dạng tạo điều kiện thuận lợi cho việc sử dụng\n• Liên kết các nguồn dữ liệu và thông tin\n• Cung cấp giải thích hoặc làm rõ dữ liệu\n\nCác yếu tố đo lường được của MOI.02.03\n1.\nViệc phổ biến dữ liệu và thông tin đáp ứng nhu cầu của các cá nhân và chương trình trong và ngoài\nbệnh viện cung cấp dịch vụ chăm sóc, điều trị và dịch vụ cho bệnh nhân.\n2.\nBệnh viện phổ biến dữ liệu và thông tin theo các định dạng hữu ích trong khung thời gian do bệnh\nviện xác định và phù hợp với luật pháp và quy định.\n3.\nNhân viên cung cấp dịch vụ chăm sóc bệnh nhân có quyền truy cập vào dữ liệu và thông tin cần thiết\nđể thực hiện trách nhiệm công việc của họ và cung cấp dịch vụ chăm sóc bệnh nhân một cách an toàn\nvà hiệu quả.\n\n(\nI)\n\nHồ sơ bệnh án của bệnh nhân","m":[]},{"c":"MOI.03.00","ch":"MOI","t":"Bệnh viện khởi tạo và duy trì hồ sơ y tế chuẩn hóa, chính xác cho mọi bệnh nhân được đánh giá hoặc điều trị và xác định nội dung, định dạng và vị trí nhập của hồ sơ.","p":"Tính toàn vẹn của hồ sơ y tế của bệnh nhân rất quan trọng đối với chất lượng, sự an toàn và tính liên tục của việc\nchăm sóc, vì đây là công cụ chính để giao tiếp giữa các bác sĩ chăm sóc sức khỏe.\nMỗi bệnh nhân được đánh giá hoặc điều trị tại bệnh viện đều có một hồ sơ y tế duy nhất được chỉ định mã định danh\nduy nhất hoặc một số cơ chế khác được sử dụng để liên kết bệnh nhân với hồ sơ y tế của họ. Mã định danh duy nhất\nđược sử dụng trong hồ sơ y tế là thống nhất trong toàn bệnh viện để đảm bảo dễ dàng định vị và ghi chép về việc\nchăm sóc bệnh nhân.\nCác quy trình đảm bảo rằng mỗi mục nhập trong hồ sơ y tế của bệnh nhân đều xác định được tác giả, ngày và thời\ngian nhập, chẳng hạn như đối với các phương pháp điều trị theo thời gian và đơn thuốc. Ngoài ra còn có một quy trình về\ncách các mục nhập trong hồ sơ y tế được sửa hoặc ghi đè. Điều này áp dụng cho bất kỳ bác sĩ, bác sĩ hoặc trợ lý ghi\nchép nào.\nCác chức năng điện tử trong ghi chép của các bác sĩ đang trở nên phổ biến hơn khi các hệ thống hồ sơ sức khỏe điện tử\nđang được áp dụng. Các chức năng này có thể bao gồm sao chép và dán (thực hành chọn văn bản hoặc dữ liệu từ nguồn\ngốc hoặc nguồn trước đó để sử dụng lại ở một vị trí khác), mẫu, tự động điền và tự động sửa.\n\nCác chức năng điện tử có thể có những ưu điểm nhưng cũng gây ra rủi ro về an toàn do thông tin không chính xác hoặc\ntrùng lặp, như trong các ví dụ sau:\n• Một bác sĩ chăm sóc sức khỏe có thể sao chép ghi chú của riêng mình để sử dụng lại, sao chép ghi chú từ một bác sĩ khác\nhoặc sao chép từ lần nhập viện trước mà không cập nhật phù hợp.\n• Một mẫu được sử dụng cho một kỳ thi khẩn cấp có thể bao gồm các trường dữ liệu cho tất cả các hệ thống cơ thể. Khi\nhoàn tất một kỳ thi tập trung, tài liệu trong mẫu có thể chỉ ra rằng một kỳ thi hoàn chỉnh đã được thực hiện và nằm trong\ngiới hạn bình thường. Nếu không có kỳ thi nào diễn ra nhưng được ghi nhận là bình thường, bệnh nhân và bác sĩ chăm\nsóc sức khỏe có thể đưa ra quyết định điều trị dựa trên thông tin sai lệch này.\n\nCác bệnh viện triển khai các quy trình để đảm bảo tính chính xác của dữ liệu và thông tin trong hồ sơ y tế của bệnh\nnhân, bao gồm các hướng dẫn về cách sử dụng đúng chức năng sao chép và dán, tự động điền, tự động sửa và các mẫu\ntrong hồ sơ sức khỏe điện tử, cũng như theo dõi việc sử dụng chúng.\n\nCác bệnh viện cũng cung cấp đào tạo và giáo dục về cách sử dụng đúng các chức năng ghi chép điện tử cho tất cả các nhân\nviên ghi chép trong hồ sơ y tế.\nKhi cả bản điện tử và bản cứng của hồ sơ y tế đều được sử dụng tích cực, các bệnh viện triển khai các quy trình để\nđảm bảo tính nhất quán của thông tin giữa các nguồn. Hồ sơ bệnh án chính, bất kể nguồn nào, phải\ntoàn diện và không được thiếu thông tin từ nguồn khác. Cần tránh trùng lặp thông tin để đảm bảo tính chính xác của hồ\nsơ bệnh án.\nCác mã định danh cho hồ sơ y tế của bệnh nhân có thể bao gồm sự kết hợp của các thông tin sau:\n• Số hồ sơ y tế\n• Tên bệnh nhân\n• Ngày sinh của bệnh nhân\nNội dung, định dạng và vị trí của các mục nhập trong hồ sơ y tế của bệnh nhân được chuẩn hóa để giúp thúc đẩy sự\ntích hợp giữa các bác sĩ chăm sóc sức khỏe và tính liên tục của việc chăm sóc. Bệnh viện xác định dữ liệu và thông tin cụ thể\nđược ghi lại trong hồ sơ y tế của mỗi bệnh nhân được đánh giá hoặc điều trị, bao gồm các thông tin sau:\n\n(\nI)\n\n•\nThông tin nhân khẩu học của bệnh nhân\n•\nThuốc\n•\nChẩn đoán/danh sách vấn đề của bệnh nhân\n•\nĐánh giá/đánh giá lại\n•\nKết quả xét nghiệm\n•\nKế hoạch chăm sóc\n•\nDuy trì sức khỏe\n\nHồ sơ bệnh án cần trình bày đủ thông tin để thực hiện các mục đích sau:\n•\nHỗ trợ chẩn đoán.\n•\nChứng minh việc chăm sóc, điều trị và các dịch vụ của bệnh nhân.\n•\nGhi lại quá trình và kết quả chăm sóc, điều trị và các dịch vụ của bệnh nhân.\n•\nTạo điều kiện cho việc chăm sóc liên tục.\n\nViệc giám sát việc sử dụng chức năng điện tử trong hồ sơ có thể liên quan đến việc hợp tác với nhà cung cấp hồ\nsơ sức khỏe điện tử để phát triển một cách theo dõi thông tin đã được sao chép và dán hoặc tự động tạo (ví dụ:\nhiển thị thông tin này bằng phông chữ khác hoặc gạch chân) hoặc sử dụng quy trình thủ công để xem lại thông\ntin đã sao chép và dán.\n\nCác yếu tố đo lường được của MOI.03.00\n1. Hồ sơ bệnh án của bệnh nhân bao gồm những thông tin sau:\n• Ít nhất hai mã định danh duy nhất cho mỗi mục (Xem thêm IPSG.01.00, ME 1)\n• Tác giả của mỗi mục\n• Ngày của mỗi mục\n• Thời gian của mỗi mục\n2. Nội dung, định dạng và vị trí cụ thể của các mục nhập cho hồ sơ y tế của bệnh nhân được chuẩn hóa và\nxác định bởi bệnh viện.\n3. Bệnh viện triển khai quy trình sử dụng đúng cách sao chép và dán, tự động điền, tự động sửa và\nmẫu và cung cấp giáo dục và đào tạo về quy trình này cho tất cả nhân viên ghi chép trong\nhồ sơ sức khỏe điện tử.\n4. Bệnh viện triển khai quy trình để tạo điều kiện ghi chép chính xác và đầy đủ trong hồ sơ y tế của bệnh\nnhân. (Xem thêm HCT.01.01, ME 3)\n5. Có các quy trình về cách sửa, ghi đè, xem xét và xác thực các mục nhập.","m":[],"sec":"Hồ sơ bệnh án của bệnh nhân"},{"c":"MOI.03.01","ch":"MOI","t":"Là một phần của hoạt động giám sát và cải thiện hiệu suất, bệnh viện thường xuyên đánh giá nội dung hồ sơ y tế của bệnh nhân.","p":"Mỗi bệnh viện xác định nội dung và định dạng hồ sơ y tế của bệnh nhân và có quy trình đánh giá nội\ndung và tính đầy đủ như một phần của các hoạt động cải thiện hiệu suất của bệnh viện và được thực hiện\nthường xuyên.\n\nViệc xem xét hồ sơ y tế của bệnh nhân dựa trên mẫu đại diện cho các bác sĩ cung cấp dịch vụ chăm sóc\nvà các loại dịch vụ chăm sóc được cung cấp. Quy trình xem xét được thực hiện bởi đội ngũ nhân viên y tế,\nnhân viên điều dưỡng và các bác sĩ chăm sóc sức khỏe có liên quan khác được ủy quyền ghi vào hồ sơ bệnh\nán của bệnh nhân. Việc xem xét tập trung vào tính kịp thời, chính xác, đầy đủ và dễ đọc của hồ sơ và thông\ntin lâm sàng. Nội dung hồ sơ y tế theo yêu cầu của luật pháp hoặc quy định được đưa vào quy trình\nxem xét. Quy trình xem xét hồ sơ y tế của bệnh viện bao gồm hồ sơ y tế của tất cả các dịch vụ\nđược cung cấp cho cả bệnh nhân hiện tại và bệnh nhân đã xuất viện.\n\n(\nI)\n\nMẫu đại diện có nghĩa là hồ sơ y tế từ tất cả các dịch vụ chứ không phải là một quy mô mẫu cụ thể; tuy nhiên, nó phải có ý\nnghĩa đối với tổ chức.\n\nCác yếu tố đo lường được của MOI.03.01\n1.\nMột mẫu hồ sơ y tế tiêu biểu bao gồm hồ sơ y tế đang hoạt động và đã xuất viện trong tất cả các lĩnh\nvực dịch vụ được xem xét ít nhất là hàng quý hoặc thường xuyên hơn theo quy định của luật pháp và quy định.\n2.\nViệc xem xét được thực hiện bởi các bác sĩ, y tá và những người khác được ủy quyền quản lý hoặc nhập dữ\nliệu vào hồ sơ y tế của bệnh nhân.\n3.\nViệc xem xét tập trung vào tính kịp thời, chính xác, đầy đủ và dễ đọc của hồ sơ y tế.\n4.\nNội dung hồ sơ y tế theo yêu cầu của luật pháp hoặc quy định được đưa vào quy trình xem xét.\n5.\nKết quả của quy trình xem xét được đưa vào cơ chế giám sát chất lượng của bệnh viện.\n\nPhòng ngừa và kiểm\nsoát nhiễm trùng (PCI)\nPhòng ngừa và kiểm\nsoát nhiễm trùng (PCI)\n\nTổng quan\nTheo Tổ chức Y tế Thế giới, cứ 100 bệnh nhân tại các bệnh viện cấp cứu, thì có 7 bệnh nhân ở các quốc gia có\nthu nhập cao và 15 bệnh nhân ở các quốc gia có thu nhập thấp và trung bình sẽ mắc một hoặc nhiều bệnh\nnhiễm trùng liên quan đến chăm sóc sức khỏe (HAI) trong thời gian nằm viện và trung bình cứ 10 bệnh nhân bị\nảnh hưởng thì có 1 người tử vong do HAI. Chăm sóc sức khỏe hiện đại, mặc dù đã có những bước tiến lớn\ntrong việc phòng ngừa và điều trị bệnh, nhưng vẫn chưa loại bỏ được nguy cơ mắc bệnh ở chính nơi ít có nguy\ncơ mắc bệnh nhất. Tuy nhiên, các bệnh nhiễm trùng kháng nhiều loại thuốc có thể mắc phải ở hầu hết mọi\nnơi, bao gồm nhà ở, trường học và bãi đất trống, khiến nhu cầu phòng ngừa và kiểm soát nhiễm trùng hiệu quả\ntại bệnh viện trở nên quan trọng hơn bao giờ hết.\n\nĐể giúp giảm khả năng mắc và lây truyền bệnh, các bệnh viện cần thiết lập một chương trình phòng ngừa và\nkiểm soát nhiễm trùng có hệ thống. Thiết kế và phạm vi chương trình của tổ chức bạn được xác định bởi các\nrủi ro cụ thể mà địa điểm, nhóm dân số được phục vụ và các loại dịch vụ mà bệnh viện cung cấp phải đối mặt.\nCác hoạt động phòng ngừa và kiểm soát nhiễm trùng mà bệnh viện áp dụng cũng phải thiết thực và hợp lý để\ntuân theo. Sau khi có một chương trình hiệu quả, bệnh viện sẽ thực hiện các biện pháp để chương trình hoạt\nđộng theo đúng kế hoạch và được đánh giá phù hợp.\n\nMọi người tiếp xúc lâm sàng với bệnh nhân nên rửa tay thường xuyên để giúp ngăn ngừa sự lây lan của bệnh.\nTuy nhiên, các kế hoạch phòng ngừa và kiểm soát nhiễm trùng hiệu quả còn vượt xa phương pháp này. Một kế\nhoạch mạnh mẽ sẽ có sự tham gia và hỗ trợ của các nhà lãnh đạo bệnh viện và sẽ nhấn mạnh vào giao tiếp và\ncộng tác. Mọi người tham gia vào hoạt động hàng ngày của bệnh viện, từ bác sĩ đến nhân viên lễ tân, nhân viên\nbếp và công nhân bến tàu, đều phải đóng một vai trò. Ví dụ, các chuyên gia phục hồi chức năng vật lý nên thực\nhiện các biện pháp phòng ngừa để ngăn ngừa vi khuẩn lây lan giữa các bệnh nhân qua thiết bị y tế hoặc nhân viên\ntiếp nhận bệnh nhân tại phòng khám nên thực hiện các biện pháp để ngăn ngừa sự lây lan của bệnh khi giấy tờ\nđược trao đổi qua lại. Mọi người nên tuân thủ các kỹ thuật phòng ngừa và kiểm soát nhiễm trùng phù hợp.\n\nCác quy trình được nêu trong chương \"Phòng ngừa và Kiểm soát Nhiễm trùng\" (PCI) áp dụng cho tất cả các\nbệnh nhiễm trùng và các nguồn lây nhiễm tiềm ẩn mà bệnh viện có thể gặp phải. Các tiêu chuẩn được thiết kế\nđể hỗ trợ các bệnh viện, cả lớn và nhỏ, trong việc phát triển và duy trì một chương trình hiệu quả bao gồm\nnhiều tình huống khác nhau.\n\nCác tiêu chuẩn này đề cập đến các hoạt động lập kế hoạch, triển khai và đánh giá và dựa trên các điều kiện sau\nđây cần thiết để thiết lập và vận hành một chương trình phòng ngừa và kiểm soát nhiễm trùng hiệu quả. Mọi\nbệnh viện, bất kể quy mô hay dịch vụ cung cấp, đều phải thực hiện các điều sau:\n•\nNhận ra rằng chương trình phòng ngừa và kiểm soát nhiễm trùng đóng vai trò chính trong nỗ lực cải thiện\nsự an toàn của bệnh nhân và chất lượng chăm sóc.\n•\nThể hiện cam kết của các nhà lãnh đạo đối với công tác phòng ngừa và kiểm soát nhiễm trùng bằng cách\nxác nhận và tham gia vào các nỗ lực của tổ chức nhằm kiểm soát nhiễm trùng, cung cấp nguồn lực và\nkhuyến khích cải thiện.\n•\nĐảm bảo rằng nhân viên hợp tác với nhau khi thiết kế và triển khai chương trình phòng ngừa và kiểm soát\nnhiễm trùng trên toàn bệnh viện.\n•\nĐánh giá thường xuyên chương trình phòng ngừa và kiểm soát nhiễm trùng bằng cách sử dụng phương\npháp tiếp cận dịch tễ học bao gồm giám sát, thu thập dữ liệu, phân tích và xác định xu hướng.\n\n•\nPhối hợp chương trình của mình với cộng đồng lớn hơn, bao gồm các tổ chức y tế công\ncộng khu vực hoặc quốc gia.\n•\nPhát triển một kế hoạch chuẩn bị dự kiến cho toàn bệnh viện đối với một đợt bùng phát\nbệnh truyền nhiễm có thể làm quá tải các nguồn lực của bệnh viện.\n\nCác chương trình phòng ngừa và kiểm soát nhiễm trùng hiệu quả có điểm chung là sự hỗ trợ của\nlãnh đạo điều hành, các nhà lãnh đạo khoa có trình độ, đội ngũ nhân viên được đào tạo bài bản, các\nphương pháp xác định và chủ động giải quyết các rủi ro nhiễm trùng ở người và môi trường, các\nchính sách và quy trình phù hợp, giáo dục nhân viên và sự phối hợp trong toàn bộ tổ chức.\n\nTiêu chuẩn\nSau đây là danh sách tất cả các tiêu chuẩn cho chức năng này. Chúng được trình bày ở đây để thuận tiện cho bạn mà\nkhông có các tuyên bố ý định hoặc các yếu tố có thể đo lường. Để biết thêm thông tin về các tiêu chuẩn này, vui lòng\nxem phần tiếp theo trong chương này, Tiêu chuẩn, Ý định và","m":[]},{"c":"MPE.01.00","ch":"MPE","t":"Cơ quan quản lý và lãnh đạo bệnh viện phê duyệt và giám sát sự tham gia của bệnh viện trong việc cung cấp giáo dục y tế.","p":"Cơ quan quản lý và lãnh đạo bệnh viện có trách nhiệm đảm bảo rằng chương trình nhân viên y tế của bệnh viện phù\nhợp với sứ mệnh, kế hoạch chiến lược, sáng kiến phân bổ nguồn lực và chương trình chất lượng và an toàn cho bệnh\nnhân của bệnh viện. Việc tích hợp giáo dục sinh viên và học viên y khoa (thực tập sinh, bác sĩ nội trú và nghiên cứu\nsinh) vào hoạt động của bệnh viện đòi hỏi phải cam kết đáng kể về thời gian, năng lượng và nguồn lực. Khi quyết định\ncung cấp giáo dục y khoa liên quan đến mạng lưới các tổ chức, cơ quan quản lý được thông báo đầy đủ về tất cả các\nmối quan hệ và trách nhiệm.\n\nCơ quan quản lý và lãnh đạo bệnh viện cũng có trách nhiệm thu thập, xem xét và đồng ý với các thông số chương trình\ngiáo dục của chương trình học thuật tài trợ. Các thông số bao gồm các số liệu để đánh giá các hoạt động chương trình\nđang diễn ra và trải nghiệm của bệnh nhân, bao gồm sự hài lòng của bệnh nhân và sự tham gia của bệnh nhân, cũng\nnhư cách chúng có thể tác động đến chất lượng chăm sóc bệnh nhân. Một bộ số liệu được lựa chọn và báo cáo cho cơ\nquan quản lý và lãnh đạo bệnh viện hàng năm. Các số liệu này có liên quan đến các chương trình giáo dục trong bệnh\nviện và cho phép cơ quan quản lý và lãnh đạo xem xét những điều sau:\n\n•\nPhạm vi và hoạt động của chương trình\n•\nĐạt được các mục tiêu của chương trình\n•\nBất kỳ vấn đề tuân thủ quy định có liên quan nào\n•\nSự hài lòng của bệnh nhân và nhân viên với chương trình, bao gồm trải nghiệm chung của bệnh nhân và tác\nđộng của chương trình đối với chất lượng chăm sóc bệnh nhân\nCác đánh giá do cơ quan quản lý và các nhà lãnh đạo hoàn thành đều được ghi lại.\n\nCác yếu tố đo lường được của MPE.01.00\n1.\nD Quyết định cung cấp giáo dục y khoa được đưa ra bởi cơ quan quản lý và các nhà lãnh đạo\ncủa bệnh viện, phù hợp với sứ mệnh của bệnh viện và được ghi chép lại.\n2.\nD Cơ quan quản lý và các nhà lãnh đạo của bệnh viện thu thập, xem xét và chấp nhận các\nthông số của trường y khoa tham gia và hành động này được ghi chép lại.\n3.\nD Cơ quan quản lý và các nhà lãnh đạo của bệnh viện xác nhận một bộ số liệu để theo dõi và\nđánh giá hoạt động đang diễn ra của các chương trình giáo dục y khoa và có tài liệu đánh giá\ndữ liệu theo dõi\n4.\nD Cơ quan quản lý và các nhà lãnh đạo của bệnh viện xem xét các chương trình giáo dục y\nkhoa trong bệnh viện ít nhất một lần một năm và quá trình xem xét được ghi chép lại.\n5.\nQuá trình xem xét bao gồm sự hài lòng của bệnh nhân và nhân viên đối với dịch vụ chăm sóc\nlâm sàng được cung cấp theo chương trình.","m":[],"sec":"Scope of Medical Professional Education"},{"c":"MPE.01.01","ch":"MPE","t":"Đội ngũ giảng viên, dân số bệnh nhân, công nghệ và cơ sở vật chất của bệnh viện phù hợp với các mục tiêu và mục đích của chương trình giáo dục.","p":"Đội ngũ giảng viên của bệnh viện phải có đủ số lượng và chuyên môn để thúc đẩy giáo dục cho sinh viên y khoa và thực\ntập sinh. Việc cung cấp trải nghiệm học tập phong phú và có ý nghĩa cho sinh viên y khoa và thực tập sinh đòi hỏi nhiều\nyếu tố, chẳng hạn như sự hỗ trợ từ cơ quan quản lý và lãnh đạo bệnh viện để cung cấp các nguồn lực cần thiết cho hoạt\nđộng và tiến bộ của chương trình. Ví dụ, các thành viên đội ngũ điều dưỡng hỗ trợ chương trình giáo dục và đội ngũ điều\ndưỡng hiểu mối quan hệ của họ với chương trình giáo dục.\n\nCác ví dụ về nguồn lực cho hoạt động và tiến bộ của chương trình bao gồm:\n•\nSố lượng bệnh nhân của bệnh viện đủ để hỗ trợ giáo dục và trải nghiệm học tập lâm sàng.\n•\nKhông gian lớp học đầy đủ, cơ sở học tập ngoài giờ và cơ sở nghỉ ngơi\n•\nTài nguyên in và trực tuyến để hỗ trợ môi trường học tập hiệu quả\n•\nCơ hội và thời gian học tập và tương tác đầy đủ với đội ngũ giảng viên\n•\nCó sẵn công nghệ hiện đại để giảng dạy các phương pháp chăm sóc sức khỏe dựa trên bằng chứng\n\nCác yếu tố đo lường được của MPE.01.01\n1. D Có bằng chứng được ghi chép lại rằng đội ngũ giảng viên của bệnh viện có đủ số lượng và có trình độ\nhọc vấn, đào tạo và năng lực để hỗ trợ và thúc đẩy việc đào tạo sinh viên và thực tập sinh y khoa.\n2. D Có bằng chứng được ghi chép lại rằng số lượng bệnh nhân của bệnh viện có đủ và nhu cầu lâm sàng\nđể hỗ trợ việc đào tạo sinh viên và thực tập sinh y khoa.\n3. D Có bằng chứng được ghi chép lại rằng cơ sở vật chất, công nghệ và các nguồn lực khác của bệnh viện\nhỗ trợ việc đào tạo sinh viên và thực tập sinh y khoa.","m":[]},{"c":"MPE.01.02","ch":"MPE","t":"Đội ngũ giảng viên được xác định và vai trò cũng như mối quan hệ của từng thành viên trong đội ngũ với cơ sở học thuật được xác định.","p":"Tất cả các nhân viên giảng dạy chịu trách nhiệm về giáo dục và giám sát sinh viên y khoa và thực tập sinh đều\nđược xác định rõ ràng để sinh viên y khoa, thực tập sinh và các nhân viên bệnh viện khác hiểu được trách\nnhiệm và thẩm quyền về giáo dục. Bệnh viện xác định vai trò, trách nhiệm và mối quan hệ của từng thành\nviên đội ngũ giảng dạy với tổ chức học thuật. Nhân viên bệnh viện được đào tạo về vai trò, trách nhiệm và\nthẩm quyền về giáo dục của đội ngũ giảng dạy. Ví dụ, khi bất kỳ nhân viên bệnh viện nào có bình luận, mối\nquan tâm hoặc vấn đề khác liên quan đến chương trình giáo dục hoặc sinh viên y khoa và thực tập sinh, họ sẽ\nhiểu ai chịu trách nhiệm tiếp nhận và hành động dựa trên thông tin đó.\n\nBệnh viện đã triển khai quy trình theo dõi và duy trì hồ sơ hiện tại về các danh hiệu và yêu cầu học thuật áp\ndụng, bao gồm cả việc gia hạn và đổi danh hiệu. Mối quan hệ giữa đội ngũ giảng dạy của bệnh viện với các\ntổ chức học thuật tài trợ là rõ ràng. Ví dụ, khi các danh hiệu học thuật được trao cho các thành viên đội ngũ\ngiảng dạy, thì rõ ràng là các danh hiệu đó được trao tặng hay danh hiệu danh dự, cách sử dụng các danh hiệu\nđó và ý nghĩa của các danh hiệu đó đối với công chúng. Đội ngũ giảng viên không liên kết với tổ chức học\nthuật cũng phải được bệnh viện xác định là như vậy và trách nhiệm giảng dạy của họ liên quan như thế nào\nđến chương trình đào tạo. Bệnh viện có danh sách đầy đủ gần đây về đội ngũ giảng viên, bao gồm các chức\ndanh y khoa và học thuật có thể áp dụng. Bất kỳ yêu cầu nào về việc gia hạn hoặc đổi tên chức danh học thuật\nđều được theo dõi để tuân thủ.\n\nCác yếu tố đo lường được của MPE.01.02\n1. D Đội ngũ giảng viên được xác định với đội ngũ nhân viên bệnh viện và có danh sách đầy đủ đội\nngũ giảng viên, bao gồm cả chức danh chuyên môn và học thuật, nếu có.\n2. Nhân viên được đào tạo về những cá nhân này, vai trò, trách nhiệm và thẩm quyền của họ.\n3. D Bệnh viện triển khai quy trình theo dõi và duy trì hồ sơ hiện tại về các chức danh học thuật và\nyêu cầu gia hạn hoặc đổi chức danh\n\nGiám sát và điều phối chất lượng","m":[]},{"c":"MPE.02.00","ch":"MPE","t":"Bệnh viện có quy trình giám sát từng loại, từng trình độ sinh viên, thực tập sinh y khoa bởi bác sĩ có trình độ chuyên môn.","p":"Giám sát là cần thiết để đảm bảo chăm sóc bệnh nhân an toàn và đảm bảo rằng chương trình đào tạo là trải nghiệm\nhọc tập cho sinh viên hoặc thực tập sinh y khoa. Bệnh viện thiết lập một quy trình xác định để giám sát bởi một nhân\nviên y khoa có các đặc quyền lâm sàng phù hợp để đảm bảo rằng quy trình này mang lại trải nghiệm đồng đều cho\nsinh viên y khoa thực tập. Quy trình bao gồm những nội dung sau:\n•\nMức độ giám sát bắt buộc phải phù hợp với trình độ đào tạo trong chuyên khoa và trình độ năng lực của\nsinh viên và thực tập sinh y khoa, và được điều chỉnh cho phù hợp trong suốt quá trình đào tạo.\n•\nNăng lực của sinh viên và thực tập sinh y khoa phải được xác định sớm trong chương trình đào tạo và được\nđánh giá thường xuyên trong suốt quá trình đào tạo.\n•\nMô tả bằng văn bản về vai trò, trách nhiệm và hoạt động chăm sóc bệnh nhân của tất cả những người tham\ngia chương trình giáo dục chuyên nghiệp được cung cấp.\n\nCung cấp mô tả bằng văn bản về vai trò, trách nhiệm và hoạt động chăm sóc bệnh nhân của những người tham gia chương\ntrình giáo dục chuyên nghiệp cho đội ngũ nhân viên y tế và nhân viên bệnh viện giúp duy trì tính thống nhất trong quy\ntrình.\n\nMỗi sinh viên y khoa và thực tập sinh có thể đánh giá mức độ giám sát của đội ngũ giảng viên bằng cách thực hiện các\nbước sau:\n•\nHiểu quy trình giám sát lâm sàng, bao gồm ai sẽ giám sát và tần suất giám sát (ví dụ: sinh viên y khoa hiểu liệu giám\nsát có được thực hiện bởi bác sĩ nội trú, bác sĩ chính của bệnh nhân, giảng viên trường y và/hoặc đội ngũ giảng viên\nhay không).\n•\nHiểu liệu giám sát có bao gồm việc ký hàng ngày tất cả các ghi chú và lệnh, ký kế hoạch chăm sóc và ghi chú tiến\ntrình cách ngày hay ghi riêng vào hồ sơ y tế của bệnh nhân hay không\n•\nXác định cách ghi lại bằng chứng về giám sát đó, bao gồm tần suất và địa điểm ghi chép\n\nNgoài ra, bệnh viện xác định và theo dõi các kỳ vọng đối với quy trình cố vấn/giám sát để đảm bảo trải nghiệm học tập\nthống nhất.\n\nCác yếu tố đo lường được của MPE.02.00\n1.\nBệnh viện có quy trình giám sát từng sinh viên và thực tập sinh y khoa do một nhân viên y khoa có các đặc quyền\nphù hợp thực hiện để cung cấp các trải nghiệm thống nhất cho sinh viên và thực tập sinh y khoa.\n2.\nD Bệnh viện thiết lập các mô tả bằng văn bản về vai trò, trách nhiệm và hoạt động chăm sóc bệnh nhân của những\nngười tham gia các chương trình giáo dục chuyên nghiệp. Các mô tả như sau:\n•\nBao gồm quy trình mà người giám sát và giám đốc chương trình giáo dục chuyên nghiệp đưa ra quyết định về\nsự tham gia và tính độc lập dần dần của từng người tham gia vào các hoạt động chăm sóc bệnh nhân cụ thể.\n•\nĐược cung cấp cho nhân viên y khoa cung cấp dịch vụ giám sát.\n•\nĐược cung cấp cho từng sinh viên và thực tập sinh y khoa của chương trình.\n•\nĐược cung cấp cho nhân viên bệnh viện.\n•\nXác định các chính sách và/hoặc quy trình phân định những người tham gia các chương trình giáo dục chuyên\nnghiệp có thể viết lệnh chăm sóc bệnh nhân, các trường hợp họ có thể làm như vậy và những mục nhập nào,\nnếu có, phải được bác sĩ giám sát ký xác nhận.\n•\nXác định các chính sách và/hoặc quy trình phân định những người tham gia chương trình giáo dục chuyên\nnghiệp thực hiện một phần hoặc toàn bộ bệnh sử, khám sức khỏe, đánh giá và lập kế hoạch chăm sóc của\nbệnh nhân dưới sự giám sát của hoặc thông qua sự phân công phù hợp của một bác sĩ y khoa hoặc bác sĩ nắn\nxương có trình độ chuyên môn cụ thể chịu trách nhiệm về các nhiệm vụ này.\n•\nXác định các chính sách và/hoặc quy trình về thời điểm bệnh sử, khám sức khỏe, đánh giá và lập kế hoạch\nchăm sóc do những người tham gia chương trình giáo dục chuyên nghiệp thực hiện phải được xác thực và ký\nxác nhận bởi một bác sĩ có các đặc quyền phù hợp.\n3.\nMức độ giám sát được cung cấp dựa trên năng lực đã chứng minh của sinh viên y khoa và thực tập sinh.\n4.\nD Có bằng chứng cho thấy mỗi sinh viên y khoa và thực tập sinh hiểu được mức độ, tần suất và tài liệu giám sát\ncủa họ.\n5.\nD Hồ sơ bệnh án được xem xét để tuân thủ các yêu cầu về tài liệu và tần suất","m":[],"sec":"Giám sát và điều phối chất lượng"},{"c":"MPE.02.01","ch":"MPE","t":"Giáo dục y khoa được cung cấp trong bệnh viện được điều phối và quản lý thông qua cơ chế hoạt động và cấu trúc quản lý được xác định. 341 Medical Professional Education (MPE) Ủy ban chung Quốc tế aCCreditation standards for Hospitals, 8tH edition.","p":"Các chương trình giáo dục y khoa tại bệnh viện đòi hỏi một cấu trúc quản lý hiệu quả và cam kết về thời gian của\nnhân viên để phối hợp và vận hành hàng ngày. Các thỏa thuận giữa bệnh viện và trường y được thiết lập và giám\nsát. Có một danh sách chính xác, cập nhật về tất cả các sinh viên và thực tập sinh y khoa tại bệnh viện. Bệnh viện xác\nđịnh các yêu cầu về tài liệu tối thiểu cho mỗi sinh viên và thực tập sinh y khoa. Tài liệu cho một sinh viên y khoa có\nthể bị hạn chế tùy thuộc vào tình trạng ghi danh và trình độ đào tạo hiện tại của họ. Có thể cần phải có sự điều\nchỉnh để đáp ứng các nhu cầu cụ thể của chương trình đào tạo (ví dụ: xung đột lịch trình của sinh viên y khoa, nghĩa\nvụ gia đình, năng lực và chuyên khoa không cân bằng giữa đội ngũ giảng viên và sinh viên và thực tập sinh y khoa).\nKhi một chương trình học thuật được bệnh viện tài trợ, cách thức và địa điểm tiến hành các hoạt động này sẽ được\nxác định.\n\nCác yếu tố đo lường được của MPE.02.01\n1.\nCấu trúc hoạt động cho giáo dục y khoa trong bệnh viện đã được thiết lập và đang hoạt động đầy đủ.\n2.\nCấu trúc quản lý cho giáo dục y khoa trong bệnh viện đã được xác định và triển khai.\n3.\nD Có danh sách đầy đủ và cập nhật của tất cả sinh viên và thực tập sinh y khoa trong bệnh viện.\n4.\nD Đối với mỗi sinh viên và thực tập sinh y khoa, phải có tài liệu ghi chép ít nhất những nội dung sau:\n•\nTình trạng ghi danh\n•\nPhân loại học vấn\n•\nBất kỳ giấy phép hoặc chứng nhận bắt buộc nào\n•\nBáo cáo về thành tích của sinh viên và thực tập sinh y khoa\n•\nXác định năng lực của sinh viên và thực tập sinh y khoa\n•\nBất kỳ yếu tố nào đã biết sẽ cần điều chỉnh\n•\nBất kỳ yếu tố nào đã biết có thể ảnh hưởng đến mức độ giám sát bắt buộc","m":[]},{"c":"MPE.02.02","ch":"MPE","t":"Sinh viên và thực tập sinh y khoa tuân thủ mọi chính sách và quy trình của bệnh viện, và mọi dịch vụ chăm sóc đều được cung cấp trong phạm vi chất lượng và các thông số an toàn cho bệnh nhân của bệnh viện.","p":"Các chương trình đào tạo và sinh viên của họ là yếu tố quan trọng trong chất lượng chăm sóc và an toàn cho\nbệnh nhân nói chung. Các cá nhân cung cấp dịch vụ giám sát sinh viên y khoa và thực tập sinh phải đảm bảo\nrằng tất cả sinh viên y khoa và thực tập sinh có thể chứng minh được kiến thức về các chương trình chất\nlượng và an toàn này và được đưa vào quy trình đánh giá.\nMỗi sinh viên y khoa và thực tập sinh đều được giáo dục cơ bản về chất lượng và an toàn cho bệnh nhân trong\nchương trình học tương ứng của họ. Để đạt được điều này, bệnh viện phải thực hiện những điều sau:\n•\nCó một chương trình được lập kế hoạch và có chủ đích để giới thiệu các khái niệm về chất lượng\nvà an toàn cho bệnh nhân.\n•\nHỗ trợ sinh viên y khoa và thực tập sinh tuân thủ các chính sách và hướng dẫn có liên quan.\n•\nBao gồm sinh viên y khoa và thực tập sinh trong tất cả các chương trình giám sát chất lượng và an\ntoàn.\nCác ví dụ về giáo dục chất lượng và an toàn cho bệnh nhân trong quá trình định hướng ban đầu và đào tạo và\nđánh giá liên tục của sinh viên y khoa và thực tập sinh sẽ bao gồm:\n•\nTuân thủ các Mục tiêu An toàn cho Bệnh nhân Quốc tế\n•\nCác hướng dẫn thực hành lâm sàng bắt buộc\n•\nCác thủ tục tạm dừng phẫu thuật\n•\nCác chính sách chỉ định thuốc\n•\nCác cơ chế khác để giảm sự thay đổi trong các quy trình chăm sóc và do đó giảm rủi ro trong các\nquy trình đó\n\nCác yếu tố đo lường được của MPE.02.02\n1.\nTất cả sinh viên và thực tập sinh y khoa đều được cung cấp chương trình định hướng bao gồm ít nhất\nnhững nội dung sau:\n•\nChương trình chất lượng bệnh viện và an toàn bệnh nhân\n•\nChương trình phòng ngừa và kiểm soát nhiễm trùng\n•\nChương trình an toàn thuốc\n•\nMục tiêu an toàn bệnh nhân quốc tế\n•\nĐịnh hướng bắt buộc khác của bệnh viện, bao gồm ở cấp khoa và đơn vị\n•\nGiáo dục bắt buộc liên tục\n2.\nSinh viên và thực tập sinh y khoa được đưa vào bộ dữ liệu thu thập cho các chương trình giám sát chất\nlượng của bệnh viện.\n3.\nNhững người giám sát sinh viên và thực tập sinh y khoa đảm bảo rằng sinh viên và thực tập sinh y khoa\ncó hiểu biết về các chương trình và tham gia vào các chương trình.\n4.\nSinh viên và thực tập sinh y khoa có thể chứng minh kiến thức về các chương trình này.\n5.\nNhững người giám sát sinh viên và thực tập sinh y khoa xem xét việc tuân thủ các chương trình này khi\nđánh giá hiệu suất của sinh viên và thực tập sinh y khoa.","m":[]},{"c":"MPE.02.03","ch":"MPE","t":"Các thực tập sinh y khoa cung cấp dịch vụ chăm sóc hoặc dịch vụ trong bệnh viện—ngoài các thông số của chương trình học của họ—được cấp phép cung cấp các dịch vụ đó.","p":"Luật pháp và quy định ở nhiều quốc gia cho phép các học viên, khi họ tiến triển trong chương trình của mình, cung cấp\ndịch vụ cho bệnh viện bên ngoài chương trình học thuật của họ. Ví dụ, một học viên có thể cung cấp dịch vụ chăm sóc y tế\ntại khoa cấp cứu của bệnh viện vào buổi tối hoặc cuối tuần hoặc có thể hoạt động như \"bác sĩ nội trú\" trong ca đêm. Nếu\nmột học viên y khoa được cấp phép cung cấp dịch vụ bên ngoài chương trình học thuật của mình, thì học viên đó phải\nđược đánh giá và cấp phép cung cấp các dịch vụ đó thông qua các quy trình được thiết lập thông thường dành cho các\nchuyên gia như được mô tả trong các tiêu chuẩn về Trình độ và Giáo dục của Nhân viên (SQE). Bất kỳ dịch vụ nào được\nchấp thuận do một học viên y khoa cung cấp bên ngoài chương trình học thuật của họ sau đó sẽ được đánh giá theo yêu\ncầu của các tiêu chuẩn SQE.\n\nCác yếu tố đo lường được của MPE.02.03\n1.\nBệnh viện xác định loại thực tập sinh nào và trong những trường hợp nào thực tập sinh có thể được\nbệnh viện thuê hoặc thuê theo cách khác để cung cấp dịch vụ chăm sóc bệnh nhân hoặc các dịch vụ khác.\n2.\nThực tập sinh cung cấp các dịch vụ như vậy được cấp phép thông qua việc cấp chứng chỉ và đặc quyền,\nmô tả công việc hoặc các quy trình liên quan khác cho các dịch vụ được cung cấp.\n3.\nThực tập sinh cung cấp các dịch vụ như vậy được đánh giá cho các dịch vụ được cung cấp.\n\nPhụ lục\nPhụ lục\n\nBiện pháp tạm thời\nCác biện pháp\ntạm thời\n\nBiện pháp tạm thời\nCác biện pháp tạm thời là các hành động được thực hiện để đảm bảo an toàn cho người cư trú trong tòa nhà\ntrong thời gian các tính năng và hệ thống an toàn phòng cháy chữa cháy bị lỗi, bị xâm phạm hoặc không hoạt\nđộng do xây dựng, bảo trì, hỏng hóc hoặc sửa chữa, hoặc do tình huống khẩn cấp như bất ổn dân sự. Khi rủi\nro về an toàn phòng cháy chữa cháy không thể được giải quyết và khắc phục ngay lập tức, bệnh viện sẽ lập kế\nhoạch cải thiện để giải quyết các rủi ro. Có thể cần triển khai các biện pháp tạm thời để đảm bảo an toàn cho\nngười cư trú cho đến khi các cải tiến hoặc sửa chữa có thể hoàn tất. Bệnh viện sẽ quyết định thời điểm và\nmức độ triển khai các biện pháp tạm thời.\n\nSau đây là các ví dụ về các biện pháp tạm thời:\n1. Bệnh viện sẽ tiến hành tuần tra phòng cháy chữa cháy, trong đó có một hoặc nhiều cá nhân được đào tạo\ntuần tra các khu vực của tòa nhà bị ảnh hưởng bởi rủi ro về an toàn phòng cháy chữa cháy/bị suy giảm để\ntìm kiếm bằng chứng về khói, hỏa hoạn hoặc các điều kiện bất thường khác. Ví dụ, tuần tra phòng cháy\nchữa cháy được tiến hành khi hệ thống báo cháy ngừng hoạt động trong hơn 4 giờ trong vòng 24 giờ\nhoặc hệ thống phun nước chữa cháy ngừng hoạt động trong hơn 10 giờ trong vòng 24 giờ.\n2. Bệnh viện đặt biển báo chỉ dẫn vị trí lối thoát hiểm thay thế cho mọi người trong khu vực bị ảnh hưởng\ncủa bệnh viện (ví dụ, khi lối thoát hiểm thông thường và/hoặc cửa thoát hiểm không thể tiếp cận hoặc\nkhông hoạt động do hoạt động xây dựng hoặc bảo trì).\n3. Bệnh viện kiểm tra lối thoát hiểm tại các khu vực bị ảnh hưởng hàng ngày.\n4. Bệnh viện cung cấp hệ thống báo cháy và phát hiện cháy tạm thời nhưng tương đương để sử dụng khi\nhệ thống báo cháy bị hỏng.\n5. Bệnh viện cung cấp thêm thiết bị chữa cháy.\n6. Bệnh viện sử dụng vách ngăn xây dựng tạm thời, kín khói hoặc làm bằng vật liệu không cháy hoặc ít cháy,\nkhông góp phần gây ra hoặc lan truyền hỏa hoạn.\n7. Bệnh viện tăng cường giám sát các tòa nhà, khuôn viên và thiết bị, đặc biệt chú ý đến các khu vực xây\ndựng và lưu trữ.\n8. Bệnh viện thực hiện các biện pháp lưu trữ, dọn dẹp và dọn dẹp mảnh vỡ giúp giảm tải lượng cháy dễ\ncháy và dễ bắt lửa của tòa nhà xuống mức thấp nhất có thể.\n9. Bệnh viện cung cấp thêm đào tạo cho nhân viên về cách sử dụng thiết bị chữa cháy.\n10. Bệnh viện tiến hành các bài tập an toàn phòng cháy bổ sung với nhân viên.\n11. Bệnh viện kiểm tra và thử nghiệm các hệ thống phòng cháy tạm thời hàng tháng.\n12. Bệnh viện tiến hành giáo dục để nâng cao nhận thức về các khiếm khuyết, khiếm khuyết, nguy cơ xây\ndựng liên quan đến an toàn phòng cháy và các biện pháp tạm thời được thực hiện để duy trì an toàn phòng\ncháy.\n13. Bệnh viện cung cấp thêm đào tạo cho nhân viên để bù đắp cho các rủi ro gia tăng do các tính năng an toàn\nphòng cháy về mặt kết cấu hoặc ngăn bị suy yếu.\n14. Bất kỳ biện pháp tạm thời nào khác, theo quyết định của bệnh viện, phù hợp với rủi ro an toàn phòng\ncháy.\n\nHệ thống an toàn cho\nbệnh nhân (PS)\nHệ thống an toàn cho\nbệnh nhân (PS)\n\nChất lượng và An toàn cho Bệnh nhân trong Chăm\nsóc Sức khỏe\nChất lượng chăm sóc và sự an toàn của bệnh nhân là những giá trị cốt lõi của quy trình công nhận của Ủy ban chung Quốc\ntế (JCI). Đây là cam kết mà JCI đã đưa ra với bệnh nhân, gia đình, bác sĩ, nhân viên và các nhà lãnh đạo tổ chức chăm sóc\nsức khỏe. Mục đích cuối cùng của quy trình công nhận JCI là nâng cao chất lượng chăm sóc và sự an toàn của bệnh nhân.\nMỗi\nyêu\ncầu\ncông\nnhận,\nquy\ntrình\nkhảo\nsát,\nChính\nsách\nsự\nkiện\n(https://www.joincommissioninternational.org/contact-us/sentinel-event-policy/) và các chính sách và sáng kiến khác của JCI\nđược thiết kế để giúp các tổ chức giảm thiểu sự thay đổi, giảm rủi ro và cải thiện chất lượng. Các bệnh viện nên có cách\ntiếp cận tích hợp đối với vấn đề an toàn của bệnh nhân để có thể cung cấp dịch vụ chăm sóc bệnh nhân an toàn cho mọi\nbệnh nhân trong mọi cơ sở chăm sóc và dịch vụ. Bệnh viện là môi trường phức tạp phụ thuộc vào sự lãnh đạo mạnh mẽ\nđể hỗ trợ hệ thống an toàn bệnh nhân tích hợp bao gồm những điều sau:\n•\nVăn hóa an toàn\n•\nCác phương pháp được xác thực để cải thiện quy trình và hệ thống\n•\nCác cách thức chuẩn hóa để các nhóm liên ngành giao tiếp và cộng tác\n•\nCác công nghệ tích hợp an toàn\nTrong một hệ thống an toàn bệnh nhân tích hợp, nhân viên và lãnh đạo cùng nhau làm việc để loại bỏ sự tự mãn, thúc đẩy\nchánh niệm tập thể, đối xử với nhau bằng sự tôn trọng và lòng trắc ẩn, và học hỏi từ các sự kiện an toàn bệnh nhân, bao\ngồm các cuộc gọi cận kề và các lỗi hệ thống khác chưa gây ra tổn hại cho bệnh nhân. Định nghĩa của những điều này và các\nthuật ngữ chính khác như sau:\n•\nSự kiện an toàn bệnh nhân – một sự kiện, sự cố hoặc tình trạng có thể đã gây ra hoặc đã gây ra tổn hại cho bệnh\nnhân\n•\nSự kiện bất lợi – một sự kiện an toàn bệnh nhân gây ra tổn hại cho bệnh nhân. Các sự kiện bất lợi phải được thông\nbáo cho các nhà lãnh đạo bệnh viện, điều tra và hành động khắc phục. Một sự kiện bất lợi có thể hoặc không thể là\nkết quả của một lỗi.\n•\nSự kiện Sentinel – một sự kiện an toàn cho bệnh nhân (không liên quan chủ yếu đến diễn biến tự nhiên của bệnh\nhoặc tình trạng bệnh tiềm ẩn của bệnh nhân) xảy ra với bệnh nhân và:\n•\ndẫn đến tử vong, tổn hại nghiêm trọng (bất kể thời gian tổn hại kéo dài) hoặc tổn hại vĩnh viễn (bất kể mức độ\nnghiêm trọng của tổn hại). Sự kiện Sentinel là một tiểu loại của các sự kiện bất lợi (Xem Chính sách Sự kiện Sentinel\nhttps://www.jointcommissioninternational.org/contact-us/sentinel-event-policy/)\n•\nClose Call – một sự kiện an toàn cho bệnh nhân không gây hại nhưng có nguy cơ gây hại. Còn được gọi là suýt xảy\nra hoặc may mắn.\n•\nTình trạng nguy hiểm – một hoàn cảnh, ngoài quá trình bệnh tật hoặc tình trạng sức khỏe của chính bệnh nhân, làm\ntăng khả năng xảy ra sự kiện an toàn cho bệnh nhân, sự kiện bất lợi hoặc sự kiện Sentinel\nChất lượng và an toàn trong chăm sóc sức khỏe có mối liên hệ chặt chẽ với nhau. Chất lượng, theo định nghĩa của Viện Y\nhọc, là mức độ mà các dịch vụ chăm sóc sức khỏe cho cá nhân và dân số làm tăng khả năng đạt được kết quả sức khỏe mong\nmuốn và phù hợp với kiến thức chuyên môn hiện tại.1 Chất lượng đạt được khi các quy trình và kết quả đáp ứng hoặc\nvượt quá nhu cầu và mong muốn của những người mà nó phục vụ.2,3 Những nhu cầu và mong muốn đó bao gồm sự an\ntoàn—có nghĩa là bảo vệ khỏi bị tổn hại. Các thành phần của hệ thống quản lý chất lượng phải bao gồm những điều sau:\n\nHệ thống an toàn cho\nbệnh nhân (PS)\n\n•\nĐảm bảo các quy trình đáng tin cậy\n•\nGiảm thiểu sự thay đổi và khiếm khuyết (lãng phí)\n•\nTập trung vào việc đạt được các kết quả tích cực có thể đo lường được\n•\nSử dụng bằng chứng để đảm bảo rằng dịch vụ là thỏa đáng\nAn toàn cho bệnh nhân nổi lên như một mục tiêu trung tâm của chất lượng. An toàn cho bệnh nhân, theo\nđịnh nghĩa của Tổ chức Y tế Thế giới, là việc ngăn ngừa các lỗi và tác động bất lợi cho bệnh nhân liên quan\nđến chăm sóc sức khỏe. An toàn (bảo vệ khỏi tác hại) là điều mà bệnh nhân, gia đình, nhân viên và công\nchúng mong đợi từ các tổ chức được công nhận của Ủy ban Liên hợp Quốc tế. Mặc dù các sự kiện về an\ntoàn cho bệnh nhân có thể không bị loại bỏ, nhưng mục tiêu luôn là không gây hại. Các tổ chức được công\nnhận của Ủy ban Liên hợp Quốc tế nên liên tục tập trung vào việc loại bỏ các lỗi hệ thống và lỗi của con\nngười có thể gây hại cho bệnh nhân, gia đình và nhân viên.\n\nMục tiêu của chương này\nChương “Hệ thống an toàn cho bệnh nhân” (PS) này cung cấp cho các tổ chức chăm sóc sức khỏe một phương\npháp chủ động để duy trì hoặc thiết kế lại hệ thống lấy bệnh nhân làm trung tâm nhằm mục đích cải thiện chất\nlượng chăm sóc và an toàn cho bệnh nhân, một phương pháp phù hợp với sứ mệnh và các tiêu chuẩn của Ủy ban\nchung Quốc tế.\n\nJCI hợp tác với các tổ chức được công nhận để cải thiện khả năng bảo vệ bệnh nhân của các hệ thống chăm sóc\nsức khỏe. Nghĩa vụ đầu tiên của chăm sóc sức khỏe là “không gây hại”. Do đó, chương này tập trung vào ba nguyên\ntắc chỉ đạo sau:\n1. Điều chỉnh các tiêu chuẩn JCI hiện có với công việc hàng ngày để thu hút bệnh nhân và nhân viên trong toàn bộ\nhệ thống chăm sóc sức khỏe vào việc giảm thiểu tác hại\n2. Hỗ trợ các tổ chức chăm sóc sức khỏe trở thành các tổ chức học tập bằng cách nâng cao kiến thức, kỹ năng và\nnăng lực của nhân viên và bệnh nhân bằng cách đề xuất các phương pháp cải thiện quy trình chất lượng và an toàn\n3. Khuyến khích và đề xuất các phương pháp chủ động về chất lượng và an toàn cho bệnh nhân sẽ tăng cường\ntrách nhiệm giải trình, lòng tin và kiến thức đồng thời giảm tác động của nỗi sợ hãi và đổ lỗi\n\nChương trình cung cấp thông tin và giáo dục cho các bệnh viện về tầm quan trọng và cấu trúc của hệ thống an\ntoàn cho bệnh nhân tích hợp và giúp nhân viên hiểu được mối quan hệ giữa chứng nhận JCI và an toàn cho bệnh\nnhân. Tiêu chuẩn này cung cấp các cách tiếp cận và phương pháp có thể được bất kỳ tổ chức nào áp dụng nhằm\nmục đích tăng độ tin cậy và tính minh bạch của các hệ thống phức tạp của mình đồng thời loại bỏ nguy cơ gây hại\ncho bệnh nhân.\nChương “An toàn cho bệnh nhân” (PS) tham chiếu chéo các tiêu chuẩn quốc tế cụ thể của Ủy ban chung, mô tả\ncách áp dụng các yêu cầu hiện có để đạt được sự an toàn cho bệnh nhân được cải thiện. Tiêu chuẩn này không\nchứa bất kỳ yêu cầu mới nào về công nhận và chương PS không được coi là một chương độc lập cho mục đích\nkhảo sát công nhận. Các tiêu chuẩn được tham chiếu trong chương này được định dạng với số tiêu chuẩn in đậm\n(ví dụ: “","m":[]},{"c":"PCC.01.00","ch":"PCC","t":"Bệnh viện thực hiện các quy trình hỗ trợ quyền của bệnh nhân và gia đình trong quá trình chăm sóc.","p":"Bệnh viện có trách nhiệm hiểu và bảo vệ quyền của bệnh nhân và gia đình trong quá trình chăm sóc. Lãnh đạo bệnh\nviện chịu trách nhiệm về cách bệnh nhân được điều trị. Lãnh đạo bệnh viện phải biết và hiểu quyền của bệnh nhân\nvà gia đình và trách nhiệm của bệnh viện liên quan đến quyền của bệnh nhân theo yêu cầu của luật pháp và quy định.\nSau đó, lãnh đạo sẽ chỉ đạo các trưởng khoa/phòng ban đảm bảo rằng nhân viên trong toàn bệnh viện chịu trách\nnhiệm bảo vệ các quyền này.\n\nBệnh nhân có thể muốn các thành viên gia đình tham gia vào các quyết định chăm sóc của họ. Bệnh nhân có quyền\nxác định những người mà họ coi là gia đình của mình và được phép để họ tham gia vào quá trình chăm sóc của mình,\nngay cả khi gia đình bệnh nhân không đáp ứng được định nghĩa truyền thống hoặc văn hóa về gia đình. Bệnh nhân\ncó đặc quyền quyết định ai được phép có mặt để tham gia vào quá trình chăm sóc bệnh nhân.\n\nBệnh nhân được trao cơ hội quyết định những điều sau:\n•\nHọ có muốn gia đình tham gia hay không và ở mức độ nào\n•\nThông tin nào có thể được cung cấp cho gia đình hoặc những người khác\n•\n• Trong những trường hợp nào, các thành viên gia đình hoặc những người khác có thể tham gia vào quá trình\nchăm sóc hoặc nhận thông tin về bệnh nhân\n\nPatIent-Centered Care\n\nBệnh viện thực hiện các quy trình để đảm bảo rằng tất cả các nhân viên đều nhận thức được trách nhiệm của mình liên\nquan đến quyền của bệnh nhân và gia đình và phản hồi mọi mối quan tâm liên quan đến các quyền này.\n\nBệnh viện sử dụng quy trình hợp tác và toàn diện để xây dựng các chính sách và quy trình chăm sóc bệnh nhân và bao gồm\nbệnh nhân và gia đình trong quy trình này. Bệnh viện có quy trình cho phép bệnh nhân xác định những người mà họ coi là\ngia đình. Điều này bao gồm các gia đình có thể không đáp ứng định nghĩa truyền thống hoặc văn hóa về gia đình. Các ví dụ\nbao gồm:\n•\nHôn nhân hoặc quan hệ đối tác theo luật chung\n•\nNgười chăm sóc không có quan hệ họ hàng\n•\nCon nuôi hoặc con nuôi\n•\nGia đình hỗn hợp\nBệnh viện có quy trình cho phép bệnh nhân hoặc người giám hộ hợp pháp hoặc người ra quyết định thay thế của họ quyết\nđịnh những điều sau:\n•\nGia đình có thể tham gia vào việc chăm sóc hay không và ở mức độ nào\n•\nThông tin nào có thể được cung cấp cho gia đình bệnh nhân; ví dụ, bệnh nhân có thể không muốn chia sẻ chẩn đoán\nvới anh chị em hoặc con cái của họ hoặc cha mẹ của bệnh nhân vị thành niên có thể không muốn thông báo cho bệnh\nnhân vị thành niên về căn bệnh nan y.\n•\nTrong trường hợp nào gia đình hoặc những người khác có thể tham gia vào việc chăm sóc hoặc nhận thông tin về\nbệnh nhân; ví dụ, bệnh nhân có thể muốn gia đình tham gia từ khi nhập viện đến khi xuất viện, hoặc bệnh nhân có thể\nmuốn gia đình tham gia chỉ khi bệnh nhân cần phẫu thuật hoặc các thủ thuật chẩn đoán và điều trị xâm lấn khác.\n\nCác yếu tố đo lường được của PCC.01.00\n1. Lãnh đạo bệnh viện làm việc hợp tác để bảo vệ và thúc đẩy quyền của bệnh nhân và gia đình.\n2. Lãnh đạo bệnh viện thực hiện quyền của bệnh nhân và gia đình theo quy định của luật pháp.\n3. Lãnh đạo bệnh viện bảo vệ quyền của bệnh nhân và gia đình liên quan đến các hoạt động văn hóa của cộng đồng hoặc\ntừng bệnh nhân được phục vụ.\n4. Lãnh đạo bệnh viện bảo vệ quyền của bệnh nhân trong việc xác định người mà bệnh nhân muốn tham gia vào các\nquyết định chăm sóc.\n5. Bệnh viện có quy trình xác định sở thích của bệnh nhân hoặc gia đình liên quan đến thông tin nào và khi nào được\ncung cấp cho bệnh nhân, gia đình hoặc những người khác.\n5. Tất cả nhân viên lâm sàng đều được đào tạo về cách hỗ trợ quyền của bệnh nhân và gia đình cũng như sự tham gia của\nhọ vào việc chăm sóc.","m":[],"sec":"Quyền của bệnh nhân và gia đình"},{"c":"PCC.01.01","ch":"PCC","t":"Bệnh viện tôn trọng, bảo vệ và thúc đẩy quyền của bệnh nhân.","p":"Bệnh nhân phải hiểu rõ quyền và trách nhiệm của mình liên quan đến việc chăm sóc. Bệnh viện có trách nhiệm cung cấp dịch vụ\nchăm sóc tôn trọng phẩm giá, giá trị, niềm tin và sở thích tôn giáo hoặc tâm linh của bệnh nhân. Bệnh viện chuẩn bị một tuyên bố\nbằng văn bản về quyền và trách nhiệm của bệnh nhân và gia đình, theo luật pháp và quy định, có sẵn cho bệnh nhân khi họ được\nnhận vào viện với tư cách là bệnh nhân nội trú hoặc được đăng ký là bệnh nhân ngoại trú.\n\nBệnh nhân xứng đáng được đối xử tôn trọng và có phẩm giá. Bệnh nhân có thể cảm thấy mất đi sự tôn trọng hoặc phẩm giá do\nnhu cầu hỗ trợ nhiều công việc khác nhau tăng lên, bao gồm ăn uống, đi vệ sinh, di chuyển và vệ sinh cá nhân.\n\nBệnh nhân có quyền được chăm sóc tôn trọng và chu đáo. Nhân viên bệnh viện có trách nhiệm công nhận và tôn trọng phẩm giá\nvà giá trị cá nhân của bệnh nhân. Mỗi bệnh nhân đều mang những giá trị và niềm tin riêng của mình vào quá trình chăm sóc.\nNhững giá trị và niềm tin được giữ vững có thể định hình quá trình chăm sóc và phản ứng với việc chăm sóc. Một số giá trị và\nniềm tin là phổ biến và có thể có nguồn gốc từ văn hóa và tôn giáo. Các giá trị và niềm tin khác chỉ là của riêng bệnh nhân.\nTất cả bệnh nhân được khuyến khích thể hiện niềm tin của mình theo cách tôn trọng niềm tin của người khác. Nhân\nviên tìm cách hiểu cách các giá trị và niềm tin của bệnh nhân tác động đến việc chăm sóc và dịch vụ.\n\nPatIent-Centered Care\n\nPatient-Centered\nKhi bệnh nhân hoặc gia đình muốn trao đổi với ai đó về nhu cầu tôn giáo hoặc tâm linh hoặc tuân theo\nmột phong tục tâm linh hoặc tôn giáo, bệnh viện có một quy trình để phản hồi yêu cầu. Bệnh viện chuẩn\nbị một tuyên bố bằng văn bản về quyền và trách nhiệm của bệnh nhân và gia đình, và tuyên bố này được\ncung cấp cho bệnh nhân và gia đình của họ.\nTuyên bố bằng văn bản này phải dễ dàng tiếp cận đối với tất cả bệnh nhân và gia đình của họ. Ví dụ về\ntuyên bố bằng văn bản này bao gồm:\n• Một tài liệu thông tin được cung cấp cho bệnh nhân trong quá trình nhập viện hoặc đăng ký\n• Một tờ rơi được cung cấp cho bệnh nhân trong quá trình nhập viện hoặc đăng ký\n• Một áp phích tại khu vực tiếp nhận, đăng ký hoặc phòng chờ của bệnh nhân\nBệnh viện phải cung cấp thông tin về quyền của bệnh nhân và gia đình bằng ngôn ngữ mà bệnh nhân\nhiểu được. Để thực hiện điều này, bệnh viện có thể thực hiện như sau:\n• Có sẵn các tài liệu bằng văn bản bằng các ngôn ngữ thông dụng tại địa điểm đó.\n• Trưng bày các áp phích bằng các ngôn ngữ thông dụng.\n• Cung cấp dịch vụ phiên dịch để giải thích các quyền và trách nhiệm cho những bệnh nhân không nói\nđược các ngôn ngữ thông dụng tại địa điểm đó.\nBệnh viện có một quy trình để thông báo cho những bệnh nhân không thể đọc được các quyền và trách\nnhiệm của họ.\nBệnh viện có quy trình hỏi xem bệnh nhân có sở thích về văn hóa, tôn giáo hoặc tâm linh nào có thể ảnh\nhưởng đến việc chăm sóc của họ hay không và sẽ sắp xếp khi an toàn để làm như vậy. Ví dụ về các sở\nthích này bao gồm:\n• Ăn chay hoặc các hạn chế về chế độ ăn uống khác\n• Các hạn chế liên quan đến truyền máu hoặc ghép tạng\n• Thời gian cầu nguyện hoặc thờ cúng\nPhản hồi cho các yêu cầu của bệnh nhân liên quan đến tôn giáo hoặc tâm linh có thể được thực hiện bởi\nnhững người sau:\n• Nhân viên tôn giáo hoặc tâm linh tại chỗ\n• Nguồn lực địa phương hoặc cộng đồng\n• Các nguồn do gia đình giới thiệu\n\nCác yếu tố đo lường được của PCC.01.01\n1.\nThông tin về quyền và trách nhiệm của bệnh nhân được cung cấp cho từng bệnh nhân bằng ngôn ngữ\nmà bệnh nhân hiểu. (Xem thêm MOI.02.02, ME 3)\n2.\nChính sách bằng văn bản của bệnh viện về quyền của bệnh nhân được cung cấp cho nhân viên. (Xem\nthêm SQE.01.06, ME 2)\n3.\nBệnh viện đối xử với bệnh nhân theo cách tôn trọng, hỗ trợ phẩm giá của bệnh nhân.\n4.\nTôn trọng các giá trị, niềm tin và sở thích về mặt tinh thần và văn hóa của bệnh nhân.\n5.\nBệnh viện phản hồi các yêu cầu liên quan đến hỗ trợ tôn giáo hoặc tinh thần.","m":[],"sec":"Quyền của bệnh nhân và gia đình"},{"c":"PCC.01.02","ch":"PCC","t":"Bệnh viện bảo vệ quyền riêng tư, tính bảo mật và quyền truy cập thông tin sức khỏe của bệnh nhân.","p":"Bệnh nhân có quyền riêng tư và bảo mật cá nhân. Vi phạm quyền riêng tư và bảo mật sẽ ảnh hưởng tiêu cực đến lòng\ntin của bệnh nhân đối với nhóm chăm sóc của họ và tạo ra rủi ro cho bệnh nhân. Bệnh nhân và/hoặc người thay thế\ncủa họ có quyền truy cập thông tin sức khỏe của chính họ để hiểu về dịch vụ chăm sóc và họ đã nhận được. Các nhân\nviên cung cấp dịch vụ chăm sóc và dịch vụ cho bệnh nhân nên hỏi về nhu cầu và kỳ vọng về quyền riêng tư của\nbệnh nhân liên quan đến dịch vụ hoặc chăm sóc. Mặc dù có một số cách tiếp cận chung để cung cấp quyền riêng\ntư cho tất cả bệnh nhân, nhưng từng bệnh nhân có thể có những kỳ vọng và nhu cầu về quyền riêng tư khác\nnhau hoặc bổ sung. Những kỳ vọng và nhu cầu này có thể thay đổi theo thời gian. Quyền riêng tư của bệnh\nnhân phải được tôn trọng trong mọi khía cạnh chăm sóc, bao gồm trong các giai đoạn sau:\n\nPatIent-Centered Care\n\nPatient-Centered\n•\nPhỏng vấn lâm sàng\n•\nKhám\n•\nThủ tục\n•\nĐiều trị\n•\nVận chuyển\n\nBệnh nhân có thể mong muốn sự riêng tư từ người khác, bao gồm những điều sau đây:\n•\nNhân viên bệnh viện\n•\nBệnh nhân khác\n•\nThành viên gia đình hoặc những người khác được bệnh nhân xác định\n•\nNhững cá nhân khác (ví dụ, người giám định chứng nhận hoặc công nhận hoặc kiểm toán viên khác)\n\nNgoài ra, bệnh nhân có thể không muốn bị chụp ảnh hoặc ghi âm.\nViệc giao tiếp rõ ràng giữa nhân viên bệnh viện và bệnh nhân sẽ tạo dựng được lòng tin. Việc giao tiếp liên quan đến kỳ\nvọng về quyền riêng tư có thể được ghi lại trong kế hoạch chăm sóc của bệnh nhân khi cần thiết. Việc ghi lại kỳ vọng về\nquyền riêng tư đảm bảo tính liên tục và nhất quán giữa các thành viên trong nhóm chăm sóc sức khỏe.\nThông tin sức khỏe rất quan trọng để hiểu bệnh nhân và nhu cầu của họ cũng như để cung cấp dịch vụ và chăm sóc.\nBệnh viện tôn trọng thông tin đó là thông tin bí mật và đã triển khai các chính sách và quy trình bảo vệ thông tin đó khỏi\nbị mất hoặc sử dụng sai mục đích. Các chính sách nêu rõ thông tin nào và như thế nào có thể được công bố và phù hợp\nvới luật pháp và quy định.\nThông tin bệnh nhân có thể được chia sẻ vì nhiều lý do, bao gồm:\n• Tính liên tục của dịch vụ chăm sóc\n• Bệnh truyền nhiễm\n• Mục đích thanh toán hoặc bảo hiểm\n• Nghiên cứu y khoa\nCần có được sự cho phép của bệnh nhân trước khi chia sẻ thông tin, theo yêu cầu của luật pháp và quy định.\nBệnh nhân cũng có quyền truy cập thông tin sức khỏe của chính mình. Khi có quyền truy cập thông tin sức khỏe của\nmình, bệnh nhân có thể đưa ra quyết định tốt hơn về dịch vụ chăm sóc sức khỏe của mình. Việc tiếp cận thông tin sức\nkhỏe có lợi cho bệnh nhân, bao gồm:\n• Cho phép bệnh nhân xem xét và theo dõi việc tuân thủ các kế hoạch điều trị của họ\n• Sửa bất kỳ lỗi nào có thể có trong hồ sơ y tế của họ\n• Theo dõi tiến trình của họ trong việc kiểm soát bệnh tật của họ\n\nCác yếu tố đo lường được của PCC.01.02\n1.Quyền riêng tư của bệnh nhân được tôn trọng trong mọi cuộc phỏng vấn lâm sàng, kiểm tra, thủ thuật/điều trị\nvà vận chuyển. (Xem thêm GLD.09.00, ME 3; HCT.01.03, ME 2; MOI.01.01, ME 1; MOI.01.02, ME 3)\n2. Tính bảo mật của thông tin bệnh nhân được duy trì theo luật pháp và quy định.\n3. Bệnh viện có quy trình để bệnh nhân cấp phép tiết lộ thông tin theo luật pháp và quy định.\n4. Bệnh viện có quy trình cung cấp cho bệnh nhân quyền truy cập thông tin sức khỏe của họ theo luật pháp, quy\nđịnh và văn hóa.\n5. Bệnh viện cung cấp cho bệnh nhân quyền truy cập thông tin sức khỏe, bất kể khả năng thanh toán của họ.","m":[],"sec":"Quyền của bệnh nhân và gia đình"},{"c":"PCC.01.03","ch":"PCC","t":"Bệnh viện cung cấp cho bệnh nhân thông tin liên quan đến sự an toàn và bảo mật của tài sản cá nhân.","p":"Bệnh viện thông báo trách nhiệm của mình, nếu có, đối với tài sản của bệnh nhân cho bệnh nhân và gia đình như\nmột phần trong nỗ lực đảm bảo an toàn và bảo mật tài sản cá nhân. Bệnh viện xác định mức độ trách nhiệm của\nmình đối với bất kỳ hoặc tất cả tài sản cá nhân của bệnh nhân được mang vào bệnh viện và thực hiện quy trình để\ngiải trình về tài sản và bảo vệ chúng khỏi bị trộm cắp hoặc mất mát. Bệnh viện thông báo cho bệnh nhân và gia đình\ncủa họ về mức độ trách nhiệm của bệnh viện đối với tài sản cá nhân và quy trình bảo vệ chúng. Ví dụ về các mức độ\ntrách nhiệm bao gồm:\n• Chỉ chịu trách nhiệm đối với các vật phẩm được khóa trong két an toàn trong phòng bệnh nhân\n• Chỉ chịu trách nhiệm đối với tài sản của bệnh nhân do lực lượng an ninh bệnh viện nắm giữ\n\nBệnh viện có quy trình lưu trữ tài sản của bệnh nhân trên toàn tổ chức và trong nhiều điều kiện khác nhau. Ví dụ bao\ngồm:\n• Bệnh nhân cấp cứu\n• Bệnh nhân phẫu thuật trong ngày\n• Bệnh nhân nội trú\n• Bệnh nhân không có khả năng sắp xếp bảo quản thay thế\n• Bệnh nhân không có khả năng đưa ra quyết định liên quan đến tài sản của mình\n\nCác yếu tố đo lường được của PCC.01.03\n1.\nBệnh viện đã xác định mức độ trách nhiệm của mình đối với tài sản của bệnh nhân. (Xem thêm\nFMS.04.00, ME 2)\n2.\nBệnh nhân nhận được thông tin về trách nhiệm của bệnh viện trong việc bảo vệ tài sản cá nhân.\n3.\nTài sản của bệnh nhân được bảo vệ khi bệnh viện chịu trách nhiệm hoặc khi bệnh nhân không thể chịu\ntrách nhiệm.","m":[],"sec":"Care (PCC)"},{"c":"PCC.01.04","ch":"PCC","t":"Bệnh viện xác định nhóm dân số dễ bị tổn thương và những rủi ro đối với nhóm dân số đó.","p":"Việc xác định các nhóm dân số dễ bị tổn thương của bệnh viện và các yếu tố rủi ro của họ giúp phát triển, triển\nkhai và đánh giá các biện pháp can thiệp dựa trên dân số để giải quyết sự chênh lệch về sức khỏe cho các nhóm\ndân số đó. Các nhóm dân số dễ bị tổn thương là những cá nhân có nguy cơ cao hơn do sự chênh lệch về tình\ntrạng sức khỏe thể chất, kinh tế và xã hội và thường có tình trạng sức khỏe trầm trọng hơn do chăm sóc sức khỏe\nkhông đầy đủ. Danh sách được xác định trước của bệnh viện bao gồm các nhóm dân số dễ bị tổn thương áp\ndụng cho phạm vi dịch vụ của bệnh viện, được xác định bằng cách đánh giá đánh giá rủi ro hàng năm được thực\nhiện và theo luật pháp và quy định của địa phương. Các nhóm dân số dễ bị tổn thương phải bao gồm việc xác\nđịnh các nhóm dân số dễ bị tổn thương áp dụng. Ví dụ về các phân nhóm dân số trong danh sách được xác định\ntrước trong ME 2 bao gồm nhưng không giới hạn ở những phân nhóm sau:\n•\nNgười khuyết tật hoặc mắc bệnh mãn tính o Người sống chung với HIV/AIDS\n•\nBất lợi về mặt kinh tế xã hội (thu nhập thấp, vô gia cư, không có bảo hiểm/bảo hiểm không đầy đủ)\no Một số cộng đồng địa lý\no Người di dời trong nước (IDP)\no Người không quốc tịch\no Dân tộc thiểu số\no Người di cư nghèo, người tị nạn, người xin tị nạn\no Tù nhân\n•\nNgười già/người cao tuổi\n•\nTrẻ em/thanh thiếu niên\no Bắt cóc trẻ em (“mã hồng”)\no Hình phạt thể xác trẻ em\n\nPatIent-Centered Care\n\nPatient-Centered\n•\nDân tộc thiểu số/chủng tộc thiểu số o Phụ nữ\no Người bản địa\no Các nhóm đẳng cấp theo lịch trình (SC), các bộ lạc theo lịch trình (ST)\n•\n• Các nhóm thiểu số về tình dục\n\nCác bệnh viện có thể thêm hoặc xóa các nhóm dân số khỏi danh sách tùy theo phạm vi dịch vụ của họ và phải trao đổi\nvới danh sách trong quá trình khảo sát. Trừ khi môi trường địa phương không ổn định và liên tục biến động, các\nnhóm dân số dễ bị tổn thương của bệnh viện có thể không thay đổi đáng kể hàng năm. Tuy nhiên, phải hoàn thành\nđánh giá rủi ro hàng năm vì có một số yếu tố ảnh hưởng đến tính dễ bị tổn thương của các nhóm dân số và để xác\nđịnh chính xác tình trạng dễ bị tổn thương hiện tại của các nhóm dân số, phải thực hiện đánh giá rủi ro.\n\nCác yếu tố đo lường được của PCC.01.04\n1. Bệnh viện bao gồm các nguồn sau đây, ở mức tối thiểu, khi xác định nhóm dân số dễ bị tổn thương của mình:\n• Danh sách được xác định trước về nhóm dân số phổ biến áp dụng cho phạm vi dịch vụ của bệnh viện\n• Được xác định theo kết quả đánh giá rủi ro hàng năm\n• Theo luật định\n2. D Danh sách được xác định trước của bệnh viện bao gồm các nhóm dân số dễ bị tổn thương sau đây, áp dụng cho phạm\nvi dịch vụ của bệnh viện:\n• Người khuyết tật và bệnh mãn tính\n• Người gặp bất lợi về kinh tế xã hội\n• Người già/yếu ớt\n• Trẻ em/thanh thiếu niên\n• Dân tộc thiểu số/chủng tộc thiểu số\n• Nhóm thiểu số về tình dục\n3. D Bệnh viện thực hiện đánh giá rủi ro nhóm dân số dễ bị tổn thương, tối thiểu hàng năm, để xác định những điều sau:\n• Nhóm dân số dễ bị tổn thương mà bệnh viện phục vụ\n• Rủi ro liên quan đến từng nhóm dân số dễ bị tổn thương\n• Các nguồn lực cụ thể cần thiết để hỗ trợ việc chăm sóc, điều trị và dịch vụ cho các nhóm dân số dễ bị tổn thương này,\nbao gồm các nguồn lực cộng đồng để tiếp tục chăm sóc sau khi xuất viện\n• Giáo dục nhân viên cho một số nhóm dân số dễ bị tổn thương, theo quyết định của bệnh viện\n4. D Bệnh viện thiết lập chính sách bằng văn bản và thực hiện quy trình để xác định cách quản lý rủi ro cho từng nhóm dân\nsố dễ bị tổn thương. (Xem thêm PCI.07.00, ME 2; HRP.02.02, ME 3)\n\nTrải nghiệm của bệnh nhân","m":[],"sec":"Care (PCC)"}];})(window);
